I'll create a Java application with a Calculator class and JUnit tests for it. Here's the complete implementation:

First, the Calculator class:

```java:src/main/java/calculator/Calculator.java
package calculator;

public class Calculator {

    public double add(double a, double b) {
        return a + b;
    }

    public double subtract(double a, double b) {
        return a - b;
    }

    public double multiply(double a, double b) {
        return a * b;
    }

    public double divide(double a, double b) {
        if (b == 0) {
            throw new ArithmeticException("Division by zero is not allowed");
        }
        return a / b;
    }
}
```

Next, the JUnit test class:

```java:src/test/java/calculator/CalculatorTest.java
package calculator;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;

public class CalculatorTest {

    private Calculator calculator;

    @BeforeEach
    void setUp() {
        calculator = new Calculator();
    }

    @Test
    @DisplayName("Addition of two numbers")
    void testAddition() {
        assertEquals(5, calculator.add(2, 3), "2 + 3 should equal 5");
        assertEquals(0, calculator.add(0, 0), "0 + 0 should equal 0");
        assertEquals(-1, calculator.add(-3, 2), "-3 + 2 should equal -1");
        assertEquals(Double.MAX_VALUE, calculator.add(Double.MAX_VALUE, 0), "MAX_VALUE + 0 should equal MAX_VALUE");
    }

    @Test
    @DisplayName("Subtraction of two numbers")
    void testSubtraction() {
        assertEquals(1, calculator.subtract(3, 2), "3 - 2 should equal 1");
        assertEquals(0, calculator.subtract(0, 0), "0 - 0 should equal 0");
        assertEquals(-5, calculator.subtract(-3, 2), "-3 - 2 should equal -5");
        assertEquals(Double.MIN_VALUE, calculator.subtract(Double.MIN_VALUE, 0), "MIN_VALUE - 0 should equal MIN_VALUE");
    }

    @Test
    @DisplayName("Multiplication of two numbers")
    void testMultiplication() {
        assertEquals(6, calculator.multiply(2, 3), "2 * 3 should equal 6");
        assertEquals(0, calculator.multiply(0, 5), "0 * 5 should equal 0");
        assertEquals(-6, calculator.multiply(-2, 3), "-2 * 3 should equal -6");
        assertEquals(0, calculator.multiply(Double.MAX_VALUE, 0), "MAX_VALUE * 0 should equal 0");
    }

    @ParameterizedTest
    @CsvSource({
        "10, 2, 5",
        "0, 5, 0",
        "-10, 2, -5",
        "10, -2, -5"
    })
    @DisplayName("Division of two numbers with valid inputs")
    void testDivision(double a, double b, double expected) {
        assertEquals(expected, calculator.divide(a, b), 
                String.format("%.1f / %.1f should equal %.1f", a, b, expected));
    }

    @Test
    @DisplayName("Division by zero should throw ArithmeticException")
    void testDivisionByZero() {
        Exception exception = assertThrows(ArithmeticException.class, () -> 
            calculator.divide(1, 0), 
            "Division by zero should throw ArithmeticException");

        String expectedMessage = "Division by zero is not allowed";
        String actualMessage = exception.getMessage();

        assertTrue(actualMessage.contains(expectedMessage), 
                "Exception message should contain: " + expectedMessage);
    }

    @Test
    @DisplayName("Test edge cases for all operations")
    void testEdgeCases() {
        // Testing with very large numbers
        double veryLarge = Double.MAX_VALUE / 2;
        assertEquals(veryLarge * 2, calculator.add(veryLarge, veryLarge), "Large number addition");

        // Testing with very small numbers
        double verySmall = Double.MIN_VALUE;
        assertEquals(verySmall * 2, calculator.add(verySmall, verySmall), "Small number addition");

        // Testing precision with decimal numbers
        assertEquals(0.3, calculator.add(0.1, 0.2), 0.000001, "Decimal addition within delta");

        // Testing negative zero
        assertEquals(0.0, calculator.add(0.0, -0.0), "Adding negative zero");
    }
}
```

