```javascript:app.js
import { createSignal, createEffect, onCleanup } from 'https://cdn.skypack.dev/@whatsup/core';
import { render } from 'https://cdn.skypack.dev/@whatsup/jsx';

function ItemListApp() {
    // Create reactive signals
    const [items, setItems] = createSignal([]);
    const [inputValue, setInputValue] = createSignal('');
    const [error, setError] = createSignal('');

    // Add a new item to the list
    const addItem = () => {
        const newItem = inputValue().trim();

        // Validate input
        if (newItem === '') {
            setError('Please enter a non-empty item');
            return;
        }

        // Clear any previous error
        setError('');

        // Add item to the list
        setItems([...items(), newItem]);

        // Clear input field
        setInputValue('');
    };

    // Remove an item from the list
    const removeItem = (index) => {
        const newItems = [...items()];
        newItems.splice(index, 1);
        setItems(newItems);
    };

    // Handle input change
    const handleInputChange = (e) => {
        setInputValue(e.target.value);
        if (error() && e.target.value.trim() !== '') {
            setError('');
        }
    };

    // Handle form submission
    const handleSubmit = (e) => {
        e.preventDefault();
        addItem();
    };

    // Keyboard event listener for Enter key
    const handleKeyDown = (e) => {
        if (e.key === 'Enter') {
            addItem();
        }
    };

    return () => (
        <div class="container">
            <h1>Whatsup Item List</h1>

            <form onSubmit={handleSubmit} class="form-group">
                <input
                    type="text"
                    value={inputValue()}
                    onInput={handleInputChange}
                    onKeyDown={handleKeyDown}
                    placeholder="Add a new item"
                />
                <button type="submit">Add Item</button>
            </form>

            {error() && <div class="error">{error()}</div>}

            <ul>
                {items().map((item, index) => (
                    <li key={index}>
                        <span>{item}</span>
                        <button 
                            class="remove" 
                            onClick={() => removeItem(index)}
                        >
                            Remove
                        </button>
                    </li>
                ))}
            </ul>

            {items().length === 0 && <p>No items added yet. Add your first item above!</p>}
        </div>
    );
}

// Render the app to the DOM
render(<ItemListApp />, document.getElementById('app'));
```

