Let's create the service layer to handle the logging:

```java:src/main/java/com/example/loggingservice/service/LoggingService.java
package com.example.loggingservice.service;

import com.example.loggingservice.model.LogEntry;
import org.springframework.stereotype.Service;
import org.tinylog.Logger;

@Service
public class LoggingService {

    public void logMessage(LogEntry logEntry) {
        String contextInfo = logEntry.getSource() != null ? 
                " [Source: " + logEntry.getSource() + "]" : "";

        String logMessage = logEntry.getMessage() + contextInfo;

        switch (logEntry.getSeverityLevel()) {
            case INFO:
                Logger.info(logMessage);
                break;
            case DEBUG:
                Logger.debug(logMessage);
                break;
            case ERROR:
                Logger.error(logMessage);
                break;
            default:
                throw new IllegalArgumentException("Unsupported severity level: " 
                        + logEntry.getSeverityLevel());
        }
    }
}
