```java:src/main/java/com/example/loggingservice/controller/LoggingController.java
package com.example.loggingservice.controller;

import com.example.loggingservice.model.ApiResponse;
import com.example.loggingservice.model.LogEntry;
import com.example.loggingservice.service.LoggingService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.tinylog.Logger;

import javax.validation.Valid;

@RestController
@RequestMapping("/api/logs")
public class LoggingController {

    private final LoggingService loggingService;

    @Autowired
    public LoggingController(LoggingService loggingService) {
        this.loggingService = loggingService;
    }

    @PostMapping
    public ResponseEntity<ApiResponse> logMessage(@Valid @RequestBody LogEntry logEntry) {
        try {
            loggingService.logMessage(logEntry);
            return ResponseEntity.ok(new ApiResponse("success", "Log message processed successfully"));
        } catch (Exception e) {
            Logger.error(e, "Error processing log message");
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(new ApiResponse("error", "Failed to process log message: " + e.getMessage()));
        }
    }
}
