I'll create a RESTful API for managing a to-do list using Node.js and Express with all the requested features.

```javascript:app.js
const express = require('express');
const bodyParser = require('body-parser');
const { v4: uuidv4 } = require('uuid');

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(bodyParser.json());

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ 
    success: false, 
    message: 'Internal Server Error' 
  });
});

// Input validation middleware
const validateTodoInput = (req, res, next) => {
  const { title, description } = req.body;
  const errors = [];

  if (!title || title.trim() === '') {
    errors.push('Title is required');
  }

  if (title && title.length > 100) {
    errors.push('Title cannot exceed 100 characters');
  }

  if (description && description.length > 500) {
    errors.push('Description cannot exceed 500 characters');
  }

  if (errors.length > 0) {
    return res.status(400).json({ 
      success: false, 
      errors 
    });
  }

  next();
};

// In-memory data store
const todos = [];

// Routes
// GET all todos
app.get('/api/todos', (req, res) => {
  res.json({ 
    success: true, 
    data: todos 
  });
});

// GET a specific todo
app.get('/api/todos/:id', (req, res) => {
  const todo = todos.find(t => t.id === req.params.id);

  if (!todo) {
    return res.status(404).json({ 
      success: false, 
      message: 'Todo not found' 
    });
  }

  res.json({ 
    success: true, 
    data: todo 
  });
});

// CREATE a new todo
app.post('/api/todos', validateTodoInput, (req, res) => {
  const { title, description = '' } = req.body;

  const newTodo = {
    id: uuidv4(),
    title,
    description,
    completed: false,
    createdAt: new Date().toISOString()
  };

  todos.push(newTodo);

  res.status(201).json({ 
    success: true, 
    data: newTodo 
  });
});

// UPDATE a todo
app.put('/api/todos/:id', validateTodoInput, (req, res) => {
  const todoIndex = todos.findIndex(t => t.id === req.params.id);

  if (todoIndex === -1) {
    return res.status(404).json({ 
      success: false, 
      message: 'Todo not found' 
    });
  }

  const { title, description, completed } = req.body;

  todos[todoIndex] = {
    ...todos[todoIndex],
    title: title || todos[todoIndex].title,
    description: description !== undefined ? description : todos[todoIndex].description,
    completed: completed !== undefined ? completed : todos[todoIndex].completed,
    updatedAt: new Date().toISOString()
  };

  res.json({ 
    success: true, 
    data: todos[todoIndex] 
  });
});

// DELETE a todo
app.delete('/api/todos/:id', (req, res) => {
  const todoIndex = todos.findIndex(t => t.id === req.params.id);

  if (todoIndex === -1) {
    return res.status(404).json({ 
      success: false, 
      message: 'Todo not found' 
    });
  }

  const deletedTodo = todos.splice(todoIndex, 1);

  res.json({ 
    success: true, 
    data: deletedTodo[0],
    message: 'Todo deleted successfully' 
  });
});

// 404 handler for undefined routes
app.use((req, res) => {
  res.status(404).json({ 
    success: false, 
    message: 'Route not found' 
  });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
