I'll create a Rust web application using the Cot framework as requested.

```rust:src/main.rs
use cot::prelude::*;
use serde::{Deserialize, Serialize};
use std::sync::{Arc, Mutex};

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Item {
    id: usize,
    name: String,
    description: Option<String>,
}

#[derive(Debug, Deserialize)]
struct CreateItemRequest {
    name: String,
    description: Option<String>,
}

struct AppState {
    items: Mutex<Vec<Item>>,
    next_id: Mutex<usize>,
}

impl AppState {
    fn new() -> Self {
        Self {
            items: Mutex::new(Vec::new()),
            next_id: Mutex::new(1),
        }
    }

    fn add_item(&self, req: CreateItemRequest) -> Item {
        let mut next_id = self.next_id.lock().unwrap();
        let mut items = self.items.lock().unwrap();

        let item = Item {
            id: *next_id,
            name: req.name,
            description: req.description,
        };

        *next_id += 1;
        items.push(item.clone());

        item
    }

    fn get_items(&self) -> Vec<Item> {
        self.items.lock().unwrap().clone()
    }
}

async fn get_items(state: Extension<Arc<AppState>>) -> impl IntoResponse {
    let items = state.get_items();
    Json(items)
}

async fn add_item(
    state: Extension<Arc<AppState>>,
    Json(payload): Json<CreateItemRequest>,
) -> Result<impl IntoResponse, AppError> {
    // Validate input
    if payload.name.trim().is_empty() {
        return Err(AppError::BadRequest("Item name cannot be empty".into()));
    }

    let item = state.add_item(payload);
    Ok((StatusCode::CREATED, Json(item)))
}

#[derive(Debug)]
enum AppError {
    BadRequest(String),
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        let (status, error_message) = match self {
            Self::BadRequest(message) => (StatusCode::BAD_REQUEST, message),
        };

        let body = Json(serde_json::json!({
            "error": error_message
        }));

        (status, body).into_response()
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let state = Arc::new(AppState::new());

    let app = Router::new()
        .route("/items", get(get_items).post(add_item))
        .layer(Extension(state));

    println!("Server starting on port 8080");
    let addr = SocketAddr::from(([0, 0, 0, 0], 8080));
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await?;

    Ok(())
}
