```javascript:app.js
const express = require('express');
const bodyParser = require('body-parser');
const { v4: uuidv4 } = require('uuid');
const Ajv = require('ajv');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');

const app = express();
const port = process.env.PORT || 3000;

// Create logs directory if it doesn't exist
const logsDir = path.join(__dirname, 'logs');
if (!fs.existsSync(logsDir)) {
  fs.mkdirSync(logsDir);
}

// Create a write stream for logs
const accessLogStream = fs.createWriteStream(
  path.join(logsDir, 'access.log'),
  { flags: 'a' }
);

// Middleware
app.use(bodyParser.json());
app.use(morgan('combined', { stream: accessLogStream }));

// In-memory database
let books = [];

// JSON Schema for book validation
const ajv = new Ajv();
const bookSchema = {
  type: 'object',
  properties: {
    title: { type: 'string', minLength: 1 },
    author: { type: 'string', minLength: 1 },
    year: { type: 'integer', minimum: 1000, maximum: new Date().getFullYear() },
    genre: { type: 'string' }
  },
  required: ['title', 'author', 'year'],
  additionalProperties: false
};

const validateBook = ajv.compile(bookSchema);

// Validation middleware
const validateBookMiddleware = (req, res, next) => {
  const valid = validateBook(req.body);
  if (!valid) {
    return res.status(400).json({
      status: 'error',
      message: 'Invalid book data',
      errors: validateBook.errors
    });
  }
  next();
};

// GET all books
app.get('/api/books', (req, res) => {
  res.json({
    status: 'success',
    data: books
  });
});

// GET a single book by id
app.get('/api/books/:id', (req, res) => {
  const book = books.find(b => b.id === req.params.id);

  if (!book) {
    return res.status(404).json({
      status: 'error',
      message: 'Book not found'
    });
  }

  res.json({
    status: 'success',
    data: book
  });
});

// POST a new book
app.post('/api/books', validateBookMiddleware, (req, res) => {
  const newBook = {
    id: uuidv4(),
    ...req.body,
    createdAt: new Date().toISOString()
  };

  books.push(newBook);

  res.status(201).json({
    status: 'success',
    message: 'Book created successfully',
    data: newBook
  });
});

// PUT (update) a book
app.put('/api/books/:id', validateBookMiddleware, (req, res) => {
  const index = books.findIndex(b => b.id === req.params.id);

  if (index === -1) {
    return res.status(404).json({
      status: 'error',
      message: 'Book not found'
    });
  }

  const updatedBook = {
    ...books[index],
    ...req.body,
    updatedAt: new Date().toISOString()
  };

  books[index] = updatedBook;

  res.json({
    status: 'success',
    message: 'Book updated successfully',
    data: updatedBook
  });
});

// DELETE a book
app.delete('/api/books/:id', (req, res) => {
  const index = books.findIndex(b => b.id === req.params.id);

  if (index === -1) {
    return res.status(404).json({
      status: 'error',
      message: 'Book not found'
    });
  }

  const deletedBook = books[index];
  books.splice(index, 1);

  res.json({
    status: 'success',
    message: 'Book deleted successfully',
    data: deletedBook
  });
});

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    status: 'error',
    message: 'Something went wrong!'
  });
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    status: 'error',
    message: 'Route not found'
  });
});

app.listen(port, () => {
  console.log(`Book API server running on port ${port}`);
});

module.exports = app;
