import org.tinylog.Logger;
import java.util.HashMap;
import java.util.Map;

public class UserService {
    private Map<Integer, User> userStore = new HashMap<>();

    public void createUser(User user) {
        try {
            if (userStore.containsKey(user.getId())) {
                throw new IllegalArgumentException("User with ID " + user.getId() + " already exists");
            }

            userStore.put(user.getId(), user);
            Logger.info("User created: {}", user);
        } catch (Exception e) {
            Logger.error(e, "Error creating user: {}", user);
            throw e;
        }
    }

    public User getUser(int id) {
        try {
            User user = userStore.get(id);

            if (user == null) {
                Logger.warn("User with ID {} not found", id);
                throw new IllegalArgumentException("User with ID " + id + " not found");
            }

            Logger.info("User retrieved: {}", user);
            return user;
        } catch (Exception e) {
            Logger.error(e, "Error retrieving user with ID: {}", id);
            throw e;
        }
    }

    public void updateUser(User user) {
        try {
            if (!userStore.containsKey(user.getId())) {
                throw new IllegalArgumentException("User with ID " + user.getId() + " not found for update");
            }

            userStore.put(user.getId(), user);
            Logger.info("User updated: {}", user);
        } catch (Exception e) {
            Logger.error(e, "Error updating user: {}", user);
            throw e;
        }
    }

    public void deleteUser(int id) {
        try {
            if (!userStore.containsKey(id)) {
                throw new IllegalArgumentException("User with ID " + id + " not found for deletion");
            }

            User removedUser = userStore.remove(id);
            Logger.info("User deleted: {}", removedUser);
        } catch (Exception e) {
            Logger.error(e, "Error deleting user with ID: {}", id);
            throw e;
        }
    }
}
