@DimensionFormula("""
    {{createdAt}}
""")
public class SalesAnalytic {

    @Dimension
    @ColumnMeta(description = "Product ID")
    private Long id;

    @Dimension
    @ColumnMeta(description = "Product Name")
    private String name;

    @Dimension
    @ColumnMeta(description = "Creation Date")
    @Temporal(timeGrain = TimeGrain.DAY)
    private Date createdAt;

    @Metric
    @ColumnMeta(description = "Total Revenue")
    private BigDecimal totalRevenue;

    @MetricFormula("SUM({{price}} * {{quantity}})")
    public BigDecimal getTotalRevenue() {
        return totalRevenue;
    }

    @Metric
    @ColumnMeta(description = "Total Units Sold")
    private Integer unitsSold;

    @MetricFormula("SUM({{quantity}})")
    public Integer getUnitsSold() {
        return unitsSold;
    }

    @Metric
    @ColumnMeta(description = "Average Price")
    private BigDecimal avgPrice;

    @MetricFormula("AVG({{price}})")
    public BigDecimal getAvgPrice() {
