import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideSettingsBuilder;
import com.yahoo.elide.core.datastore.DataStore;
import com.yahoo.elide.core.dictionary.EntityDictionary;
import com.yahoo.elide.core.exceptions.ExceptionMappers;
import com.yahoo.elide.core.exceptions.HttpStatusException;
import com.yahoo.elide.core.filter.dialect.RSQLFilterDialect;
import com.yahoo.elide.core.request.route.Route;
import com.yahoo.elide.datastores.aggregation.AggregationDataStore;
import com.yahoo.elide.datastores.aggregation.core.QueryEngine;
import com.yahoo.elide.datastores.aggregation.queryengines.sql.SQLQueryEngine;
import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.datastores.multiplex.MultiplexManager;
import com.yahoo.elide.jsonapi.JsonApiMapper;
import com.yahoo.elide.jsonapi.JsonApiSettings;
import com.yahoo.elide.spring.config.ElideConfigProperties;
import jakarta.persistence.EntityManager;
import jakarta.persistence.EntityManagerFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpStatus;
import org.springframework.web.server.ResponseStatusException;

import java.util.Map;
import java.util.TimeZone;
import java.util.function.Function;

@Configuration
public class ElideConfig {

    @Bean
    public Elide initializeElide(EntityManagerFactory entityManagerFactory,
                                ElideConfigProperties elideConfigProperties) {
        // Create JPA data store
        DataStore jpaDataStore = new JpaDataStore(
                emf -> entityManagerFactory.createEntityManager(),
                em -> em.getTransaction().begin(),
                em -> em.getTransaction().commit(),
                em -> em.getTransaction().rollback(),
                em -> em.close()
        );

        // Create the entity dictionary
        EntityDictionary dictionary = EntityDictionary.builder().build();

        // Create analytic store with SQL query engine
        QueryEngine queryEngine = new SQLQueryEngine(entityManagerFactory);
        AggregationDataStore analyticsStore = new AggregationDataStore(queryEngine, dictionary);

        // Combine data stores
        DataStore multiplexDataStore = new MultiplexManager(jpaDataStore, analyticsStore);

        // Set up exception handlers for better error messages
        Map<Class<? extends Exception>, Function<Exception, HttpStatusException>> mappers = 
            ExceptionMappers.getMappers();

        // Configure and build the Elide instance
        ElideSettingsBuilder builder = new ElideSettingsBuilder(multiplexDataStore)
                .withEntityDictionary(dictionary)
                .withDefaultMaxPageSize(elideConfigProperties.getMaxPageSize())
                .withDefaultPageSize(elideConfigProperties.getPageSize())
                .withJsonApiMapper(new JsonApiMapper(dictionary))
                .withExceptionMappers(mappers)
                .withISO8601Dates("yyyy-MM-dd'T'HH:mm:ss'Z'", TimeZone.getTimeZone("UTC"))
                .withJsonApiPath("/api/v1/data")
                .withGraphQLApiPath("/api/v1/graphql");

        // Add JSON-API settings
        builder.withJsonApiSettings(JsonApiSettings.builder().build());

        return new Elide(builder.build());
    }
}
