```java:src/main/java/com/example/controller/ApiController.java
package com.example.controller;

import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideResponse;
import com.yahoo.elide.core.exceptions.HttpStatusException;
import com.yahoo.elide.core.request.route.Route;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api/v1")
public class ApiController {
    private static final Logger logger = LoggerFactory.getLogger(ApiController.class);

    private final Elide elide;

    @Autowired
    public ApiController(Elide elide) {
        this.elide = elide;
    }

    @GetMapping("/data/{resource}")
    public ResponseEntity<String> jsonApiGet(
            @PathVariable String resource,
            @RequestParam Map<String, String> allRequestParams) {
        try {
            String path = "/" + resource;
            ElideResponse<String> response = elide.get(path, allRequestParams, null);
            return ResponseEntity.status(response.getStatus()).body(response.getBody());
        } catch (HttpStatusException e) {
            logger.error("Error processing GET request", e);
            return ResponseEntity.status(e.getStatus()).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error", e);
            return ResponseEntity.status(500).body("Internal Server Error");
        }
    }

    @PostMapping("/data/{resource}")
    public ResponseEntity<String> jsonApiPost(
            @PathVariable String resource,
            @RequestBody String body) {
        try {
            String path = "/" + resource;
            ElideResponse<String> response = elide.post(path, body, null);
            return ResponseEntity.status(response.getStatus()).body(response.getBody());
        } catch (HttpStatusException e) {
            logger.error("Error processing POST request", e);
            return ResponseEntity.status(e.getStatus()).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error", e);
            return ResponseEntity.status(500).body("Internal Server Error");
        }
    }

    @PatchMapping("/data/{resource}/{id}")
    public ResponseEntity<String> jsonApiPatch(
            @PathVariable String resource,
            @PathVariable String id,
            @RequestBody String body) {
        try {
            String path = "/" + resource + "/" + id;
            ElideResponse<String> response = elide.patch(Route.builder().path(path).apiVersion(1).build(), body, null);
            return ResponseEntity.status(response.getStatus()).body(response.getBody());
        } catch (HttpStatusException e) {
            logger.error("Error processing PATCH request", e);
            return ResponseEntity.status(e.getStatus()).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error", e);
            return ResponseEntity.status(500).body("Internal Server Error");
        }
    }

    @DeleteMapping("/data/{resource}/{id}")
    public ResponseEntity<String> jsonApiDelete(
            @PathVariable String resource,
            @PathVariable String id) {
        try {
            String path = "/" + resource + "/" + id;
            ElideResponse<String> response = elide.delete(path, "", null);
            return ResponseEntity.status(response.getStatus()).body(response.getBody());
        } catch (HttpStatusException e) {
            logger.error("Error processing DELETE request", e);
            return ResponseEntity.status(e.getStatus()).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error", e);
            return ResponseEntity.status(500).body("Internal Server Error");
        }
    }

    @PostMapping("/graphql")
    public ResponseEntity<String> graphQLPost(@RequestBody String body) {
        try {
            ElideResponse<String> response = elide.post("/graphql", body, null);
            return ResponseEntity.status(response.getStatus()).body(response.getBody());
        } catch (HttpStatusException e) {
            logger.error("Error processing GraphQL request", e);
            return ResponseEntity.status(e.getStatus()).body(e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error", e);
            return ResponseEntity.status(500).body("Internal Server Error");
        }
    }
}
