Here's a Flask web application that serves as a RESTful API for managing a collection of books:

```python
from flask import Flask, request, jsonify
import logging
from datetime import datetime
import uuid
import re
from functools import wraps

app = Flask(__name__)

# Configure logging
logging.basicConfig(
    filename='book_api.log',
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)

# In-memory storage for books
books = {}

# Middleware for request logging
@app.before_request
def log_request_info():
    logging.info(f"Request: {request.method} {request.path} - IP: {request.remote_addr}")
    logging.info(f"Headers: {dict(request.headers)}")
    if request.data:
        logging.info(f"Body: {request.data.decode('utf-8')}")

# Data validation decorator
def validate_book_data(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        data = request.get_json()
        if not data:
            logging.warning("Invalid request: No JSON data provided")
            return jsonify({"error": "Request must contain valid JSON data"}), 400

        required_fields = ['title', 'author', 'publication_date']
        missing_fields = [field for field in required_fields if field not in data]
        if missing_fields:
            logging.warning(f"Invalid request: Missing fields {missing_fields}")
            return jsonify({"error": f"Missing required fields: {missing_fields}"}), 400

        # Validate title and author are non-empty strings
        if not isinstance(data.get('title'), str) or not data.get('title').strip():
            return jsonify({"error": "Title must be a non-empty string"}), 400

        if not isinstance(data.get('author'), str) or not data.get('author').strip():
            return jsonify({"error": "Author must be a non-empty string"}), 400

        # Validate publication date format (YYYY-MM-DD)
        date_pattern = re.compile(r'^\d{4}-\d{2}-\d{2}$')
        if not date_pattern.match(data.get('publication_date', '')):
            return jsonify({"error": "Publication date must be in YYYY-MM-DD format"}), 400

        try:
            datetime.strptime(data.get('publication_date'), '%Y-%m-%d')
        except ValueError:
            return jsonify({"error": "Invalid publication date"}), 400

        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/books', methods=['GET'])
def get_all_books():
    logging.info("Retrieving all books")
    return jsonify(list(books.values())), 200

@app.route('/api/books/<book_id>', methods=['GET'])
def get_book(book_id):
    if book_id not in books:
        logging.warning(f"Book with ID {book_id} not found")
        return jsonify({"error": "Book not found"}), 404

    logging.info(f"Retrieved book with ID {book_id}")
    return jsonify(books[book_id]), 200

@app.route('/api/books', methods=['POST'])
@validate_book_data
def create_book():
    data = request.get_json()

    book_id = str(uuid.uuid4())
    new_book = {
        "id": book_id,
        "title": data['title'],
        "author": data['author'],
        "publication_date": data['publication_date']
    }

    books[book_id] = new_book
    logging.info(f"Created new book with ID {book_id}")

    return jsonify(new_book), 201

@app.route('/api/books/<book_id>', methods=['PUT'])
@validate_book_data
def update_book(book_id):
    if book_id not in books:
        logging.warning(f"Book with ID {book_id} not found for update")
        return jsonify({"error": "Book not found"}), 404

    data = request.get_json()

    books[book_id]['title'] = data['title']
    books[book_id]['author'] = data['author']
    books[book_id]['publication_date'] = data['publication_date']

    logging.info(f"Updated book with ID {book_id}")
    return jsonify(books[book_id]), 200

@app.route('/api/books/<book_id>', methods=['DELETE'])
def delete_book(book_id):
    if book_id not in books:
        logging.warning(f"Book with ID {book_id} not found for deletion")
        return jsonify({"error": "Book not found"}), 404

    deleted_book = books.pop(book_id)
    logging.info(f"Deleted book with ID {book_id}")

    return jsonify({"message": "Book deleted successfully", "book": deleted_book}), 200

@app.errorhandler(400)
def bad_request(error):
    logging.error(f"Bad request: {error}")
    return jsonify({"error": "Bad request"}), 400

@app.errorhandler(404)
def not_found(error):
    logging.error(f"Resource not found: {error}")
    return jsonify({"error": "Resource not found"}), 404

@app.errorhandler(405)
def method_not_allowed(error):
    logging.error(f"Method not allowed: {error}")
    return jsonify({"error": "Method not allowed"}), 405

@app.errorhandler(500)
def server_error(error):
    logging.error(f"Server error: {error}")
    return jsonify({"error": "Internal server error"}), 500

if __name__ == '__main__':
    app.run(debug=True)
```

I'll create a web application using a reactive JavaScript framework. Since you mentioned "Whatsup" (which might be a typo for a framework), I'll use React which is a popular reactive UI framework.

```jsx:src/App.jsx
import { useState, useEffect } from 'react';
import UserList from './components/UserList';
import LoadingSpinner from './components/LoadingSpinner';
import ErrorMessage from './components/ErrorMessage';
import './App.css';

function App() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchUsers = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch('https://jsonplaceholder.typicode.com/users');

      if (!response.ok) {
        throw new Error(`HTTP error! Status: ${response.status}`);
      }

      const data = await response.json();
      setUsers(data);
    } catch (err) {
      setError(err.message || 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  return (
    <div className="app">
      <h1>User Management</h1>
      <button onClick={fetchUsers}>Refresh Users</button>

      {loading && <LoadingSpinner />}
      {error && <ErrorMessage message={error} />}
      {!loading && !error && <UserList users={users} />}
    </div>
  );
}

export default App;
```

