Here's a C++ application that implements a directed acyclic graph (DAG) for task processing using the CGraph framework:

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <functional>
#include <memory>
#include <stdexcept>
#include <cgraph/cgraph.h>
#include <cgraph/pipeline.h>

class Task {
public:
    Task(const std::string& id, const std::function<void()>& func)
        : id_(id), func_(func) {}

    void execute() {
        func_();
    }

    const std::string& getId() const {
        return id_;
    }

private:
    std::string id_;
    std::function<void()> func_;
};

class TaskDAG {
public:
    TaskDAG() = default;

    void addTask(const std::string& id, const std::function<void()>& func) {
        if (tasks_.find(id) != tasks_.end()) {
            throw std::runtime_error("Task ID already exists: " + id);
        }

        tasks_[id] = std::make_shared<Task>(id, func);
        graph_->add_vertex(id);
    }

    void addDependency(const std::string& fromId, const std::string& toId) {
        if (tasks_.find(fromId) == tasks_.end()) {
            throw std::runtime_error("Task not found: " + fromId);
        }

        if (tasks_.find(toId) == tasks_.end()) {
            throw std::runtime_error("Task not found: " + toId);
        }

        try {
            graph_->add_edge(fromId, toId);

            // Check for cycles
            if (!cgraph::is_acyclic(*graph_)) {
                graph_->remove_edge(fromId, toId);
                throw std::runtime_error("Adding this dependency would create a cycle");
            }
        } catch (const std::exception& e) {
            throw std::runtime_error("Failed to add dependency: " + std::string(e.what()));
        }
    }

    void execute() {
        cgraph::GPipeline pipeline(*graph_);

        pipeline.on_vertex_execute([this](const std::string& id) {
            std::cout << "Executing task: " << id << std::endl;
            tasks_[id]->execute();
        });

        pipeline.on_vertex_complete([](const std::string& id) {
            std::cout << "Completed task: " << id << std::endl;
        });

        pipeline.on_error([](const std::string& id, const std::exception& e) {
            std::cerr << "Error in task " << id << ": " << e.what() << std::endl;
        });

        pipeline.execute();

        std::cout << "\nExecution complete. Results:" << std::endl;
        for (const auto& [id, _] : tasks_) {
            std::cout << "- " << id << ": " << (pipeline.is_vertex_complete(id) ? "Completed" : "Failed") << std::endl;
        }
    }

    void printGraph() const {
        std::cout << "Task Dependencies:" << std::endl;
        for (const auto& vertex : graph_->vertices()) {
            std::cout << "- " << vertex << " depends on:";
            auto deps = graph_->in_edges(vertex);
            if (deps.empty()) {
                std::cout << " (none)";
            } else {
                for (const auto& dep : deps) {
                    std::cout << " " << dep;
                }
            }
            std::cout << std::endl;
        }
    }

private:
    std::map<std::string, std::shared_ptr<Task>> tasks_;
    std::shared_ptr<cgraph::Graph> graph_ = std::make_shared<cgraph::Graph>();
};

int main() {
    try {
        TaskDAG dag;

        // Define some example tasks
        dag.addTask("init", []() { 
            std::cout << "Initializing resources..." << std::endl; 
        });

        dag.addTask("load_data", []() { 
            std::cout << "Loading data from storage..." << std::endl; 
        });

        dag.addTask("process", []() { 
            std::cout << "Processing data..." << std::endl; 
        });

        dag.addTask("analyze", []() { 
            std::cout << "Analyzing results..." << std::endl; 
        });

        dag.addTask("report", []() { 
            std::cout << "Generating report..." << std::endl; 
        });

        dag.addTask("cleanup", []() { 
            std::cout << "Cleaning up resources..." << std::endl; 
        });

        // Define dependencies
        dag.addDependency("init", "load_data");
        dag.addDependency("load_data", "process");
        dag.addDependency("process", "analyze");
        dag.addDependency("analyze", "report");
        dag.addDependency("report", "cleanup");

        // Display the task graph
        dag.printGraph();

        // Execute the tasks
        std::cout << "\nExecuting tasks:\n" << std::endl;
        dag.execute();

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
