package com.library.service;

import com.library.proto.AddBookResponse;
import com.library.proto.Book;
import com.library.proto.GetBookRequest;
import com.library.proto.LibraryServiceGrpc;
import com.library.proto.ListBooksRequest;
import com.library.proto.ListBooksResponse;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

public class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {
    private static final Logger logger = LoggerFactory.getLogger(LibraryServiceImpl.class);

    // Using ConcurrentHashMap for thread safety
    private final Map<String, Book> books = new ConcurrentHashMap<>();

    @Override
    public void addBook(Book request, StreamObserver<AddBookResponse> responseObserver) {
        try {
            logger.info("Received request to add book: {}", request.getTitle());

            // Generate ID if not provided
            String bookId = request.getId().isEmpty() ? UUID.randomUUID().toString() : request.getId();

            Book book = Book.newBuilder()
                    .setId(bookId)
                    .setTitle(request.getTitle())
                    .setAuthor(request.getAuthor())
                    .setYear(request.getYear())
                    .build();

            books.put(bookId, book);

            AddBookResponse response = AddBookResponse.newBuilder()
                    .setId(bookId)
                    .setSuccess(true)
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();

            logger.info("Book added successfully with ID: {}", bookId);
        } catch (Exception e) {
            logger.error("Error adding book", e);
            responseObserver.onError(
                    Status.INTERNAL
                            .withDescription("Internal error while adding book")
                            .withCause(e)
                            .asRuntimeException()
            );
        }
    }

    @Override
    public void getBook(GetBookRequest request, StreamObserver<Book> responseObserver) {
        try {
            String id = request.getId();
            logger.info("Received request to get book with ID: {}", id);

            if (books.containsKey(id)) {
                responseObserver.onNext(books.get(id));
                responseObserver.onCompleted();
                logger.info("Book found and returned successfully");
            } else {
                logger.warn("Book with ID {} not found", id);
                responseObserver.onError(
                        Status.NOT_FOUND
                                .withDescription("Book with ID " + id + " not found")
                                .asRuntimeException()
                );
            }
        } catch (Exception e) {
            logger.error("Error retrieving book", e);
            responseObserver.onError(
                    Status.INTERNAL
                            .withDescription("Internal error while retrieving book")
                            .withCause(e)
                            .asRuntimeException()
            );
        }
    }

    @Override
    public void listBooks(ListBooksRequest request, StreamObserver<ListBooksResponse> responseObserver) {
        try {
            logger.info("Received request to list all books");

            ListBooksResponse.Builder responseBuilder = ListBooksResponse.newBuilder();
            books.values().forEach(responseBuilder::addBooks);

            responseObserver.onNext(responseBuilder.build());
            responseObserver.onCompleted();

            logger.info("Returned {} books", books.size());
        } catch (Exception e) {
            logger.error("Error listing books", e);
            responseObserver.onError(
                    Status.INTERNAL
                            .withDescription("Internal error while listing books")
                            .withCause(e)
                            .asRuntimeException()
            );
        }
    }
}
