```src/main/java/com/library/client/LibraryClient.java
package com.library.client;

import com.library.proto.AddBookResponse;
import com.library.proto.Book;
import com.library.proto.GetBookRequest;
import com.library.proto.LibraryServiceGrpc;
import com.library.proto.ListBooksRequest;
import com.library.proto.ListBooksResponse;
import io.grpc.Channel;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.concurrent.TimeUnit;

public class LibraryClient {
    private static final Logger logger = LoggerFactory.getLogger(LibraryClient.class);

    private final LibraryServiceGrpc.LibraryServiceBlockingStub blockingStub;

    public LibraryClient(Channel channel) {
        blockingStub = LibraryServiceGrpc.newBlockingStub(channel);
    }

    public void addBook(String title, String author, int year) {
        logger.info("Adding book: {}", title);
        Book book = Book.newBuilder()
                .setTitle(title)
                .setAuthor(author)
                .setYear(year)
                .build();

        try {
            AddBookResponse response = blockingStub.addBook(book);
            logger.info("Book added with ID: {}", response.getId());
        } catch (StatusRuntimeException e) {
            logger.error("Failed to add book", e);
        }
    }

    public Book getBook(String id) {
        logger.info("Getting book with ID: {}", id);
        GetBookRequest request = GetBookRequest.newBuilder()
                .setId(id)
                .build();

        try {
            return blockingStub.getBook(request);
        } catch (StatusRuntimeException e) {
            logger.error("Failed to get book", e);
            return null;
        }
    }

    public void listBooks() {
        logger.info("Listing all books");
        ListBooksRequest request = ListBooksRequest.newBuilder().build();

        try {
            ListBooksResponse response = blockingStub.listBooks(request);
            logger.info("Found {} books", response.getBooksCount());

            for (Book book : response.getBooksList()) {
                logger.info("Book: {} by {} ({})", book.getTitle(), book.getAuthor(), book.getYear());
            }
        } catch (StatusRuntimeException e) {
            logger.error("Failed to list books", e);
        }
    }

    public static void main(String[] args) throws InterruptedException {
        String target = "localhost:50051";

        ManagedChannel channel = ManagedChannelBuilder.forTarget(target)
                .usePlaintext()
                .build();

        try {
            LibraryClient client = new LibraryClient(channel);

            // Add some books
            client.addBook("The Great Gatsby", "F. Scott Fitzgerald", 1925);
            client.addBook("To Kill a Mockingbird", "Harper Lee", 1960);
            client.addBook("1984", "George Orwell", 1949);

            // List all books
            client.listBooks();

        } finally {
            channel.shutdownNow().awaitTermination(5, TimeUnit.SECONDS);
        }
    }
}
