        assertEquals(0, calculator.add(0, 0), DELTA);
        assertEquals(-5, calculator.add(-2, -3), DELTA);
        assertEquals(0, calculator.add(-5, 5), DELTA);
        assertEquals(Double.MAX_VALUE, calculator.add(Double.MAX_VALUE, 0), DELTA);
    }

    @Test
    public void testSubtraction() {
        assertEquals(-1, calculator.subtract(2, 3), DELTA);
        assertEquals(0, calculator.subtract(0, 0), DELTA);
        assertEquals(1, calculator.subtract(-2, -3), DELTA);
        assertEquals(-10, calculator.subtract(-5, 5), DELTA);
        assertEquals(Double.MAX_VALUE, calculator.subtract(Double.MAX_VALUE, 0), DELTA);
    }

    @Test
    public void testMultiplication() {
        assertEquals(6, calculator.multiply(2, 3), DELTA);
        assertEquals(0, calculator.multiply(0, 5), DELTA);
        assertEquals(6, calculator.multiply(-2, -3), DELTA);
        assertEquals(-15, calculator.multiply(-5, 3), DELTA);
        assertEquals(0, calculator.multiply(0, 0), DELTA);
    }

    @Test
    public void testDivision() {
        assertEquals(2, calculator.divide(6, 3), DELTA);
        assertEquals(0, calculator.divide(0, 5), DELTA);
