// src/main/java/com/example/userprofile/UserProfileServiceImpl.java
package com.example.userprofile;

import io.grpc.Status;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.regex.Pattern;

public class UserProfileServiceImpl extends UserProfileServiceGrpc.UserProfileServiceImplBase {
    private static final Logger logger = LoggerFactory.getLogger(UserProfileServiceImpl.class);
    private final Map<String, UserProfileResponse> profiles = new ConcurrentHashMap<>();
    private static final Pattern EMAIL_PATTERN = Pattern.compile("^[A-Za-z0-9+_.-]+@(.+)$");

    @Override
    public void createUserProfile(UserProfileRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received create user profile request");

        try {
            validateCreateRequest(request);

            String id = UUID.randomUUID().toString();
            UserProfileResponse profile = UserProfileResponse.newBuilder()
                    .setId(id)
                    .setEmail(request.getEmail())
                    .setName(request.getName())
                    .setAge(request.getAge())
                    .build();

            profiles.put(id, profile);
            logger.info("Created user profile with ID: {}", id);
            responseObserver.onNext(profile);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            logger.warn("Invalid create request: {}", e.getMessage());
            responseObserver.onError(Status.INVALID_ARGUMENT
                    .withDescription(e.getMessage())
                    .asRuntimeException());
        }
    }

    @Override
    public void getUserProfile(UserProfileIdRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received get user profile request for ID: {}", request.getId());

        if (request.getId().isEmpty()) {
            logger.warn("Invalid get request: Empty ID");
            responseObserver.onError(Status.INVALID_ARGUMENT
                    .withDescription("User ID cannot be empty")
                    .asRuntimeException());
            return;
        }

        UserProfileResponse profile = profiles.get(request.getId());
        if (profile == null) {
            logger.warn("User not found with ID: {}", request.getId());
            responseObserver.onError(Status.NOT_FOUND
                    .withDescription("User not found with ID: " + request.getId())
                    .asRuntimeException());
            return;
        }

        logger.info("Retrieved user profile with ID: {}", request.getId());
        responseObserver.onNext(profile);
        responseObserver.onCompleted();
    }

    @Override
    public void updateUserProfile(UpdateUserProfileRequest request, StreamObserver<UserProfileResponse> responseObserver) {
        logger.info("Received update user profile request for ID: {}", request.getId());

        try {
            validateUpdateRequest(request);

            UserProfileResponse existingProfile = profiles.get(request.getId());
            if (existingProfile == null) {
                logger.warn("User not found for update with ID: {}", request.getId());
                responseObserver.onError(Status.NOT_FOUND
                        .withDescription("User not found with ID: " + request.getId())
                        .asRuntimeException());
                return;
            }

            UserProfileResponse updatedProfile = UserProfileResponse.newBuilder()
                    .setId(existingProfile.getId())
                    .setEmail(existingProfile.getEmail())
                    .setName(request.getName())
                    .setAge(request.getAge())
                    .build();

            profiles.put(request.getId(), updatedProfile);
            logger.info("Updated user profile with ID: {}", request.getId());
            responseObserver.onNext(updatedProfile);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            logger.warn("Invalid update request: {}", e.getMessage());
            responseObserver.onError(Status.INVALID_ARGUMENT
                    .withDescription(e.getMessage())
                    .asRuntimeException());
        }
    }

    private void validateCreateRequest(UserProfileRequest request) {
        if (request.getEmail().isEmpty()) {
            throw new IllegalArgumentException("Email cannot be empty");
        }

        if (!EMAIL_PATTERN.matcher(request.getEmail()).matches()) {
            throw new IllegalArgumentException("Invalid email format");
        }

        if (request.getName().isEmpty()) {
            throw new IllegalArgumentException("Name cannot be empty");
        }

        if (request.getAge() < 0) {
            throw new IllegalArgumentException("Age cannot be negative");
        }
    }

    private void validateUpdateRequest(UpdateUserProfileRequest request) {
        if (request.getId().isEmpty()) {
            throw new IllegalArgumentException("User ID cannot be empty");
        }

        if (request.getName().isEmpty()) {
            throw new IllegalArgumentException("Name cannot be empty");
        }

        if (request.getAge() < 0) {
            throw new IllegalArgumentException("Age cannot be negative");
        }
    }
}
