fn button_system(
    mut next_state: ResMut<NextState<GameState>>,
    mut interaction_query: Query<
        (&Interaction, &mut BackgroundColor),
        (Changed<Interaction>, Or<(With<StartButton>, With<RestartButton>)>),
    >,
    start_button_query: Query<Entity, With<StartButton>>,
    restart_button_query: Query<Entity, With<RestartButton>>,
    mut game_data: ResMut<GameData>,
) {
    for (interaction, mut color) in &mut interaction_query {
        match *interaction {
            Interaction::Pressed => {
                *color = Color::rgb(0.35, 0.35, 0.35).into();

                if !start_button_query.is_empty() {
                    game_data.player_health = 3;
                    next_state.set(GameState::InGame);
                } else if !restart_button_query.is_empty() {
                    game_data.player_health = 3;
                    next_state.set(GameState::InGame);
                }
            }
            Interaction::Hovered => {
                *color = Color::rgb(0.25, 0.25, 0.25).into();
            }
            Interaction::None => {
                *color = Color::rgb(0.15, 0.15, 0.15).into();
            }
        }
    }
}

