    }

    for entity in ui_query.iter() {
        commands.entity(entity).despawn_recursive();
    }
}

fn player_movement(
    keyboard_input: Res<Input<KeyCode>>,
    time: Res<Time>,
    mut player_query: Query<&mut Transform, With<Player>>,
) {
    let mut player_transform = player_query.single_mut();
    let mut direction = Vec3::ZERO;

    if keyboard_input.pressed(KeyCode::Left) || keyboard_input.pressed(KeyCode::A) {
        direction.x -= 1.0;
    }
    if keyboard_input.pressed(KeyCode::Right) || keyboard_input.pressed(KeyCode::D) {
        direction.x += 1.0;
    }
    if keyboard_input.pressed(KeyCode::Up) || keyboard_input.pressed(KeyCode::W) {
        direction.y += 1.0;
    }
    if keyboard_input.pressed(KeyCode::Down) || keyboard_input.pressed(KeyCode::S) {
        direction.y -= 1.0;
    }

    if direction != Vec3::ZERO {
        direction = direction.normalize();
        player_transform.translation += direction * PLAYER_SPEED * time.delta_seconds();
    }
}

fn collision_detection(
    mut player_query: Query<(&mut Player, &Transform)>,
    collider_query: Query<&Transform, (With<Collider>, Without<Player>)>,
    mut health_text_query: Query<&mut Text, With<GameUI>>,
    time: Res<Time>,
    mut game_data: ResMut<GameData>,
) {
    let (mut player, player_transform) = player_query.single_mut();
    let player_size = PLAYER_SIZE;
    let player_position = player_transform.translation;

    for transform in collider_query.iter() {
        let collision = collide(
            player_position,
            player_size,
            transform.translation,
            transform.sprite_size().unwrap_or(OBSTACLE_SIZE),
        );

        if let Some(collision) = collision {
            // Handle collision
            player.health = player.health.saturating_sub(1);
            game_data.player_health = player.health;

            // Update UI
            if let Ok(mut text) = health_text_query.get_single_mut() {
                text.sections[1].value = player.health.to_string();
            }

            // Bounce back
            let mut reflection_vector = Vec3::ZERO;
            match collision {
                Collision::Left => reflection_vector.x = 1.0,
                Collision::Right => reflection_vector.x = -1.0,
                Collision::Top => reflection_vector.y = -1.0,
                Collision::Bottom => reflection_vector.y = 1.0,
                Collision::Inside => {}
            }

            // Move player away from collision
            let mut player_transform = player_query.single_mut().1;
            player_transform.translation += reflection_vector * PLAYER_SPEED * time.delta_seconds() * 2.0;

            // Only handle one collision per frame
            break;
        }
    }
}

fn check_health(
    player_query: Query<&Player>,
    mut next_state: ResMut<NextState<GameState>>,
) {
    let player = player_query.single();
    if player.health == 0 {
        next_state.set(GameState::GameOver);
    }
}
