import { h, app, useState, useEffect } from 'https://cdn.jsdelivr.net/npm/whatsup@latest/+esm';

// State management using useState hook
function NotesApp() {
  const [notes, setNotes] = useState([]);
  const [newNote, setNewNote] = useState('');
  const [deleteId, setDeleteId] = useState(null);

  // Add a new note
  function addNote() {
    if (newNote.trim()) {
      setNotes([...notes, { id: Date.now(), text: newNote }]);
      setNewNote('');
    }
  }

  // Delete a note
  function deleteNote(id) {
    setNotes(notes.filter(note => note.id !== id));
    setDeleteId(null);
  }

  // Confirmation dialog component
  function* ConfirmDialog() {
    if (deleteId === null) return null;

    return (
      <div class="modal">
        <div class="modal-content">
          <h3>Delete Note</h3>
          <p>Are you sure you want to delete this note?</p>
          <div class="modal-buttons">
            <button onClick={() => setDeleteId(null)}>Cancel</button>
            <button onClick={() => deleteNote(deleteId)}>Delete</button>
          </div>
        </div>
      </div>
    );
  }

  // Note input component
  function* NoteInput() {
    return (
      <div class="note-form">
        <h2>Add New Note</h2>
        <textarea 
          value={newNote} 
          onInput={e => setNewNote(e.target.value)}
          placeholder="Enter your note here..."
        ></textarea>
        <button onClick={addNote}>Add Note</button>
      </div>
    );
  }

  // Note list component
  function* NoteList() {
    if (notes.length === 0) {
      return <p>No notes yet. Add one above!</p>;
    }

    return (
      <div>
        <h2>Your Notes</h2>
        {notes.map(note => (
          <div class="note" key={note.id}>
            <div>{note.text}</div>
            <button onClick={() => setDeleteId(note.id)}>Delete</button>
          </div>
        ))}
      </div>
    );
  }

  // Main app component
  return function* () {
    return (
      <div>
        <h1>Notes App</h1>
        <NoteInput />
        <NoteList />
        <ConfirmDialog />
      </div>
    );
  };
}

