I'll create a temperature sensor module with unit tests using CppUTest.

First, let's create the temperature sensor header file:

```temperature_sensor.h
#ifndef TEMPERATURE_SENSOR_H
#define TEMPERATURE_SENSOR_H

typedef struct {
    float current_temperature;
    float threshold;
    int initialized;
} TemperatureSensor;

// Initialize the temperature sensor with a default temperature and threshold
void temperature_sensor_init(TemperatureSensor* sensor, float initial_temp, float threshold);

// Read the current temperature from the sensor
float temperature_sensor_read(TemperatureSensor* sensor);

// Set a new temperature value (simulating a reading)
void temperature_sensor_set_temperature(TemperatureSensor* sensor, float temperature);

// Check if temperature exceeds threshold and return 1 if alert needed, 0 otherwise
int temperature_sensor_check_alert(TemperatureSensor* sensor);

#endif // TEMPERATURE_SENSOR_H
```

Now the implementation file:

```temperature_sensor.c
#include "temperature_sensor.h"

void temperature_sensor_init(TemperatureSensor* sensor, float initial_temp, float threshold) {
    sensor->current_temperature = initial_temp;
    sensor->threshold = threshold;
    sensor->initialized = 1;
}

float temperature_sensor_read(TemperatureSensor* sensor) {
    if (!sensor->initialized) {
        return -999.0f; // Error value if not initialized
    }
    return sensor->current_temperature;
}

void temperature_sensor_set_temperature(TemperatureSensor* sensor, float temperature) {
    if (sensor->initialized) {
        sensor->current_temperature = temperature;
    }
}

int temperature_sensor_check_alert(TemperatureSensor* sensor) {
    if (!sensor->initialized) {
        return 0;
    }
    return (sensor->current_temperature > sensor->threshold) ? 1 : 0;
}
```

