```temperature_sensor_test.cpp
#include "CppUTest/TestHarness.h"
#include "temperature_sensor.h"

TEST_GROUP(TemperatureSensorTests) {
    TemperatureSensor sensor;

    void setup() {
        // Initialize before each test
    }

    void teardown() {
        // Clean up after each test
    }
};

TEST(TemperatureSensorTests, InitializeSensor) {
    temperature_sensor_init(&sensor, 25.0f, 30.0f);

    CHECK_EQUAL(1, sensor.initialized);
    DOUBLES_EQUAL(25.0f, sensor.current_temperature, 0.001f);
    DOUBLES_EQUAL(30.0f, sensor.threshold, 0.001f);
}

TEST(TemperatureSensorTests, ReadTemperature) {
    temperature_sensor_init(&sensor, 25.0f, 30.0f);

    DOUBLES_EQUAL(25.0f, temperature_sensor_read(&sensor), 0.001f);
}

TEST(TemperatureSensorTests, SetTemperature) {
    temperature_sensor_init(&sensor, 25.0f, 30.0f);
    temperature_sensor_set_temperature(&sensor, 28.5f);

    DOUBLES_EQUAL(28.5f, temperature_sensor_read(&sensor), 0.001f);
}

TEST(TemperatureSensorTests, AlertWhenExceedsThreshold) {
    temperature_sensor_init(&sensor, 25.0f, 30.0f);

    CHECK_EQUAL(0, temperature_sensor_check_alert(&sensor)); // Below threshold

    temperature_sensor_set_temperature(&sensor, 31.0f);
    CHECK_EQUAL(1, temperature_sensor_check_alert(&sensor)); // Above threshold
}

TEST(TemperatureSensorTests, NoAlertWhenEqualToThreshold) {
    temperature_sensor_init(&sensor, 25.0f, 30.0f);
    temperature_sensor_set_temperature(&sensor, 30.0f);

    CHECK_EQUAL(0, temperature_sensor_check_alert(&sensor)); // Equal to threshold
}

TEST(TemperatureSensorTests, EdgeCaseMinimumValue) {
    temperature_sensor_init(&sensor, -273.15f, 30.0f); // Absolute zero

    DOUBLES_EQUAL(-273.15f, temperature_sensor_read(&sensor), 0.001f);
    CHECK_EQUAL(0, temperature_sensor_check_alert(&sensor));
}

TEST(TemperatureSensorTests, EdgeCaseMaximumValue) {
    temperature_sensor_init(&sensor, 1000000.0f, 30.0f); // Very high temp

    DOUBLES_EQUAL(1000000.0f, temperature_sensor_read(&sensor), 0.001f);
    CHECK_EQUAL(1, temperature_sensor_check_alert(&sensor));
}

TEST(TemperatureSensorTests, UninitializedSensorReturnsErrorValue) {
    sensor.initialized = 0;

    DOUBLES_EQUAL(-999.0f, temperature_sensor_read(&sensor), 0.001f);
    CHECK_EQUAL(0, temperature_sensor_check_alert(&sensor));
}
