import os
import random
import string
import logging
from datetime import datetime
from cement import App, Controller, ex
from cement.core.exc import CementRenderError, ArgumentError
from cement.utils.misc import init_defaults

# Configuration settings
CONFIG = init_defaults('password_generator')
CONFIG['password_generator']['log_file'] = 'password_generator.log'

class PasswordGenerator(Controller):
    class Meta:
        label = 'base'
        description = 'Generate secure random passwords'
        arguments = [
            (['-l', '--length'], {
                'help': 'Password length (12-64)',
                'type': int,
                'default': 12
            }),
            (['-n', '--numbers'], {
                'help': 'Include numbers',
                'action': 'store_true',
                'dest': 'numbers'
            }),
            (['-s', '--special'], {
                'help': 'Include special characters',
                'action': 'store_true',
                'dest': 'special'
            })
        ]

    @ex(help='Generate a secure random password')
    def generate(self):
        try:
            length = self.app.pargs.length
            include_numbers = self.app.pargs.numbers
            include_special = self.app.pargs.special

            # Validate password length
            if length < 12 or length > 64:
                self.app.log.error("Password length must be between 12 and 64 characters")
                self.app.render({"error": "Invalid password length"}, 'error')
                return

            # Generate password
            password = self._generate_password(length, include_numbers, include_special)

            # Log generation attempt
            self.app.log.info(f"Password generated with length={length}, numbers={include_numbers}, special={include_special}")

            # Display output
            data = {
                "success": True,
                "password": password,
                "length": length,
                "includes_numbers": include_numbers,
                "includes_special": include_special,
                "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            }
            self.app.render(data, 'password')

        except Exception as e:
            self.app.log.error(f"Error generating password: {str(e)}")
            self.app.render({"error": str(e)}, 'error')

    def _generate_password(self, length, include_numbers, include_special):
        chars = string.ascii_letters
        if include_numbers:
            chars += string.digits
        if include_special:
            chars += string.punctuation

        return ''.join(random.choice(chars) for _ in range(length))

class PasswordGeneratorApp(App):
    class Meta:
        label = 'password_generator'
        handlers = [PasswordGenerator]
        config_defaults = CONFIG
        extensions = ['colorlog', 'json']
        output_handler = 'jinja2'
        template_dir = os.path.join(os.path.dirname(__file__), 'templates')

        # Register template handlers
        template_handler = 'jinja2'

def main():
    # Setup logging
    logging.basicConfig(
        filename='password_generator.log',
        level=logging.INFO,
        format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
    )

    with PasswordGeneratorApp() as app:
        # Define templates
        app.template.add({
            'password': """
{{ "Success!" | green }}
Generated password: {{ password | bold }}
Length: {{ length }}
Includes numbers: {{ includes_numbers }}
Includes special characters: {{ includes_special }}
Generated at: {{ timestamp }}
""",
            'error': """
{{ "Error!" | red }}
{{ error | yellow }}
"""
        })

        try:
            app.run()
        except Exception as e:
            app.log.error(f"Application error: {e}")

if __name__ == '__main__':
    main()
