#include <iostream>
#include <string>
#include <vector>
#include <chrono>
#include <filesystem>
#include <fstream>
#include <opencv2/opencv.hpp>
#include "cgraph.h"

namespace fs = std::filesystem;

struct ProcessingStats {
    std::string filename;
    double loadTime;
    double filterTime;
    double saveTime;
    bool success;
    std::string errorMessage;
};

class ImageLoader : public CGraph::Element {
private:
    std::string inputDir;
    std::vector<std::string> filePaths;
    size_t currentIndex = 0;

public:
    ImageLoader(const std::string& dir) : inputDir(dir) {
        for (const auto& entry : fs::directory_iterator(inputDir)) {
            if (entry.path().extension() == ".jpg" || 
                entry.path().extension() == ".png" || 
                entry.path().extension() == ".jpeg") {
                filePaths.push_back(entry.path().string());
            }
        }
    }

    bool hasNext() const override {
        return currentIndex < filePaths.size();
    }

    void process() override {
        auto start = std::chrono::high_resolution_clock::now();

        ProcessingStats stats;
        stats.filename = fs::path(filePaths[currentIndex]).filename().string();

        try {
            cv::Mat image = cv::imread(filePaths[currentIndex]);
            if (image.empty()) {
                stats.success = false;
                stats.errorMessage = "Failed to load image: " + filePaths[currentIndex];
            } else {
                stats.success = true;

                auto output = std::make_shared<std::pair<cv::Mat, ProcessingStats>>();
                output->first = image;
                output->second = stats;

                pushOutput("image", output);
            }
        } catch (const std::exception& e) {
            stats.success = false;
            stats.errorMessage = e.what();
        }

        auto end = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed = end - start;
        stats.loadTime = elapsed.count();

        currentIndex++;
    }
};

class ImageFilter : public CGraph::Element {
public:
    void process() override {
        auto input = getInput<std::pair<cv::Mat, ProcessingStats>>("image");
        auto start = std::chrono::high_resolution_clock::now();

        cv::Mat grayImage;
        cv::cvtColor(input->first, grayImage, cv::COLOR_BGR2GRAY);

        auto end = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed = end - start;

        auto output = std::make_shared<std::pair<cv::Mat, ProcessingStats>>(input->second);
        output->first = grayImage;
        output->second.filterTime = elapsed.count();

        pushOutput("filtered_image", output);
    }
};

class ImageSaver : public CGraph::Element {
private:
    std::string outputDir;
    std::vector<ProcessingStats> allStats;

public:
    ImageSaver(const std::string& dir) : outputDir(dir) {
        if (!fs::exists(outputDir)) {
            fs::create_directories(outputDir);
        }
    }

    void process() override {
        auto input = getInput<std::pair<cv::Mat, ProcessingStats>>("filtered_image");
        auto start = std::chrono::high_resolution_clock::now();

        ProcessingStats stats = input->second;

        try {
            std::string outputPath = outputDir + "/gray_" + stats.filename;
            bool saved = cv::imwrite(outputPath, input->first);

            if (!saved) {
                stats.success = false;
                stats.errorMessage = "Failed to save image: " + outputPath;
            }
        } catch (const std::exception& e) {
            stats.success = false;
            stats.errorMessage = e.what();
        }

        auto end = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed = end - start;
        stats.saveTime = elapsed.count();

        allStats.push_back(stats);
    }

    void saveStats() const {
        std::ofstream file(outputDir + "/stats.json");
        file << "[\n";
        for (size_t i = 0; i < allStats.size(); ++i) {
            const auto& stats = allStats[i];
            file << "  {\n";
            file << "    \"filename\": \"" << stats.filename << "\",\n";
            file << "    \"loadTime\": " << stats.loadTime << ",\n";
            file << "    \"filterTime\": " << stats.filterTime << ",\n";
            file << "    \"saveTime\": " << stats.saveTime << ",\n";
            file << "    \"totalTime\": " << (stats.loadTime + stats.filterTime + stats.saveTime) << ",\n";
            file << "    \"success\": " << (stats.success ? "true" : "false");
            if (!stats.success) {
                file << ",\n    \"error\": \"" << stats.errorMessage << "\"";
            }
            file << "\n  }";
            if (i < allStats.size() - 1) {
                file << ",";
            }
            file << "\n";
        }
        file << "]\n";
    }
};

int main(int argc, char** argv) {
    if (argc < 3) {
        std::cerr << "Usage: " << argv[0] << " <input_directory> <output_directory>\n";
        return 1;
    }

    std::string inputDir = argv[1];
    std::string outputDir = argv[2];

    CGraph::Graph graph;

    auto loader = std::make_shared<ImageLoader>(inputDir);
    auto filter = std::make_shared<ImageFilter>();
    auto saver = std::make_shared<ImageSaver>(outputDir);

    graph.addElement("loader", loader);
    graph.addElement("filter", filter);
    graph.addElement("saver", saver);

    graph.connect("loader", "image", "filter", "image");
    graph.connect("filter", "filtered_image", "saver", "filtered_image");

    graph.setMaxParallelism(4);

    graph.execute();

    std::dynamic_pointer_cast<ImageSaver>(saver)->saveStats();

    return 0;
}
