```cpp:cgraph.h
#pragma once
#include <string>
#include <memory>
#include <unordered_map>
#include <vector>
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <functional>
#include <atomic>

namespace CGraph {

class Element {
protected:
    std::unordered_map<std::string, std::shared_ptr<void>> inputs;
    std::unordered_map<std::string, std::shared_ptr<void>> outputs;

public:
    virtual ~Element() = default;

    virtual bool hasNext() const { return true; }
    virtual void process() = 0;

    template<typename T>
    void pushOutput(const std::string& name, const std::shared_ptr<T>& data) {
        outputs[name] = std::static_pointer_cast<void>(data);
    }

    template<typename T>
    std::shared_ptr<T> getInput(const std::string& name) {
        return std::static_pointer_cast<T>(inputs[name]);
    }

    void setInput(const std::string& name, std::shared_ptr<void> data) {
        inputs[name] = data;
    }

    std::shared_ptr<void> getOutput(const std::string& name) {
        return outputs[name];
    }

    void clearOutputs() {
        outputs.clear();
    }
};

struct Connection {
    std::string sourceElement;
    std::string sourcePort;
    std::string targetElement;
    std::string targetPort;
};

class Graph {
private:
    std::unordered_map<std::string, std::shared_ptr<Element>> elements;
    std::vector<Connection> connections;
    int maxParallelism = 1;

    struct Task {
        std::string elementName;
        std::shared_ptr<Element> element;
    };

    std::queue<Task> taskQueue;
    std::mutex queueMutex;
    std::condition_variable condition;
    std::atomic<bool> done{false};
    std::vector<std::thread> workers;

public:
    void addElement(const std::string& name, std::shared_ptr<Element> element) {
        elements[name] = element;
    }

    void connect(const std::string& sourceElement, const std::string& sourcePort,
                 const std::string& targetElement, const std::string& targetPort) {
        connections.push_back({sourceElement, sourcePort, targetElement, targetPort});
    }

    void setMaxParallelism(int num) {
        maxParallelism = num;
    }

    void execute() {
        // Create worker threads
        for (int i = 0; i < maxParallelism; ++i) {
            workers.emplace_back([this] {
                while (true) {
                    Task task;
                    {
                        std::unique_lock<std::mutex> lock(queueMutex);
                        condition.wait(lock, [this] { 
                            return !taskQueue.empty() || done; 
                        });

                        if (done && taskQueue.empty()) {
                            return;
                        }

                        task = taskQueue.front();
                        taskQueue.pop();
                    }

                    task.element->process();

                    // Propagate outputs to connected elements
                    for (const auto& conn : connections) {
                        if (conn.sourceElement == task.elementName) {
                            auto output = task.element->getOutput(conn.sourcePort);
                            if (output && elements.find(conn.targetElement) != elements.end()) {
                                elements[conn.targetElement]->setInput(conn.targetPort, output);

                                // Add target element to task queue
                                {
                                    std::unique_lock<std::mutex> lock(queueMutex);
                                    taskQueue.push({conn.targetElement, elements[conn.targetElement]});
                                }
                                condition.notify_one();
                            }
                        }
                    }

                    task.element->clearOutputs();

                    // If this is a source element and has more data, add it back to the queue
                    if (task.element->hasNext()) {
                        std::unique_lock<std::mutex> lock(queueMutex);
                        taskQueue.push(task);
                        condition.notify_one();
                    }
                }
            });
        }

        // Add source elements to task queue
        for (const auto& [name, element] : elements) {
            bool isSource = true;
            for (const auto& conn : connections) {
                if (conn.targetElement == name) {
                    isSource = false;
                    break;
                }
            }

            if (isSource) {
                std::unique_lock<std::mutex> lock(queueMutex);
                taskQueue.push({name, element});
            }
        }
        condition.notify_all();

        // Wait for all tasks to complete
        while (true) {
            std::this_thread::sleep_for(std::chrono::milliseconds(100));

            std::unique_lock<std::mutex> lock(queueMutex);
            if (taskQueue.empty()) {
                done = true;
                condition.notify_all();
                break;
            }
        }

        for (auto& worker : workers) {
            worker.join();
        }
    }
};

} // namespace CGraph
