package com.example.inventory;

import io.grpc.*;
import io.grpc.health.v1.HealthCheckResponse;
import io.grpc.protobuf.services.HealthStatusManager;
import io.grpc.protobuf.services.ProtoReflectionService;
import io.grpc.netty.shaded.io.grpc.netty.NettyServerBuilder;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContext;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContextBuilder;
import io.prometheus.client.CollectorRegistry;
import io.prometheus.client.Counter;
import io.prometheus.client.Histogram;
import io.prometheus.client.exporter.HTTPServer;

import java.io.File;
import java.io.IOException;
import java.util.concurrent.TimeUnit;

public class InventoryServer {
    private final int port;
    private final Server server;
    private final HealthStatusManager healthStatusManager;

    public static final CollectorRegistry registry = new CollectorRegistry();
    public static final Counter rpcCallCounter = Counter.build()
            .name("inventory_rpc_calls_total")
            .help("Total RPC calls")
            .labelNames("method")
            .register(registry);

    public static final Histogram rpcDurationSeconds = Histogram.build()
            .name("inventory_rpc_duration_seconds")
            .help("RPC call duration in seconds")
            .labelNames("method")
            .register(registry);

    public InventoryServer(int port) throws IOException {
        this.port = port;
        this.healthStatusManager = new HealthStatusManager();

        SslContext sslContext = SslContextBuilder.forServer(
                new File("server.crt"), 
                new File("server.key")).build();

        this.server = NettyServerBuilder.forPort(port)
                .addService(new InventoryServiceImpl())
                .addService(ProtoReflectionService.newInstance())
                .addService(healthStatusManager.getHealthService())
                .useTransportSecurity(sslContext)
                .intercept(new MetricsInterceptor())
                .build();
    }

    public void start() throws IOException {
        server.start();
        healthStatusManager.setStatus("inventory.InventoryService", HealthCheckResponse.ServingStatus.SERVING);

        // Start Prometheus metrics server
        HTTPServer metricsServer = new HTTPServer(port + 1, registry);

        System.out.println("Server started, listening on port " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down server...");
            try {
                InventoryServer.this.stop();
            } catch (InterruptedException e) {
                e.printStackTrace(System.err);
            }
        }));
    }

    public void stop() throws InterruptedException {
        if (server != null) {
            server.shutdown().awaitTermination(30, TimeUnit.SECONDS);
        }
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws Exception {
        int port = 50051;
        final InventoryServer server = new InventoryServer(port);
        server.start();
        server.blockUntilShutdown();
    }
}
