package com.example.inventory;

import io.grpc.Context;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.util.HashMap;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

public class InventoryServiceImpl extends InventoryServiceGrpc.InventoryServiceImplBase {
    private final Map<String, Product> inventory = new ConcurrentHashMap<>();

    public InventoryServiceImpl() {
        // Initialize with some sample products
        inventory.put("p1", Product.newBuilder()
                .setId("p1")
                .setName("Laptop")
                .setQuantity(100)
                .setPrice(999.99)
                .build());
        inventory.put("p2", Product.newBuilder()
                .setId("p2")
                .setName("Smartphone")
                .setQuantity(200)
                .setPrice(699.99)
                .build());
        inventory.put("p3", Product.newBuilder()
                .setId("p3")
                .setName("Headphones")
                .setQuantity(15)
                .setPrice(149.99)
                .build());
    }

    @Override
    public void updateStock(StockUpdateRequest request, StreamObserver<StockUpdateResponse> responseObserver) {
        String productId = request.getProductId();
        int quantityChange = request.getQuantityChange();

        if (!Context.current().isCancelled()) {
            if (inventory.containsKey(productId)) {
                Product oldProduct = inventory.get(productId);
                Product updatedProduct = Product.newBuilder(oldProduct)
                        .setQuantity(oldProduct.getQuantity() + quantityChange)
                        .build();

                inventory.put(productId, updatedProduct);

                responseObserver.onNext(StockUpdateResponse.newBuilder()
                        .setSuccess(true)
                        .setUpdatedProduct(updatedProduct)
                        .build());
                responseObserver.onCompleted();
            } else {
                responseObserver.onError(Status.NOT_FOUND
                        .withDescription("Product not found: " + productId)
                        .asRuntimeException());
            }
        }
    }

    @Override
    public void subscribeLowStockAlerts(LowStockSubscriptionRequest request,
                                      StreamObserver<LowStockAlert> responseObserver) {
        int threshold = request.getThreshold();

        // Check initial low stock items
        inventory.values().stream()
                .filter(product -> product.getQuantity() < threshold)
                .forEach(product -> {
                    if (!Context.current().isCancelled()) {
                        responseObserver.onNext(LowStockAlert.newBuilder()
                                .setProduct(product)
                                .setThreshold(threshold)
                                .setCurrentQuantity(product.getQuantity())
                                .build());
                    }
                });

        // In a real implementation, we would set up a listener for inventory changes
        // and continue sending alerts as they occur. For this example, we'll just
        // simulate a few more alerts after a delay.

        new Thread(() -> {
            try {
                for (int i = 0; i < 5 && !Context.current().isCancelled(); i++) {
                    Thread.sleep(2000);

                    // Simulate a stock change
                    String[] productIds = {"p1", "p2", "p3"};
                    String productId = productIds[i % productIds.length];

                    Product oldProduct = inventory.get(productId);
                    int newQuantity = Math.max(0, oldProduct.getQuantity() - 5);
                    Product updatedProduct = Product.newBuilder(oldProduct)
                            .setQuantity(newQuantity)
                            .build();

                    inventory.put(productId, updatedProduct);

                    if (newQuantity < threshold && !Context.current().isCancelled()) {
                        responseObserver.onNext(LowStockAlert.newBuilder()
                                .setProduct(updatedProduct)
                                .setThreshold(threshold)
                                .setCurrentQuantity(newQuantity)
                                .build());
                    }
                }

                if (!Context.current().isCancelled()) {
                    responseObserver.onCompleted();
                }
            } catch (InterruptedException e) {
                responseObserver.onError(Status.INTERNAL
                        .withDescription("Interrupted")
                        .asRuntimeException());
            }
        }).start();
    }
}
