package com.example.inventory;

import io.grpc.*;
import io.grpc.health.v1.HealthCheckRequest;
import io.grpc.health.v1.HealthCheckResponse;
import io.grpc.health.v1.HealthGrpc;
import io.grpc.netty.shaded.io.grpc.netty.GrpcSslContexts;
import io.grpc.netty.shaded.io.grpc.netty.NettyChannelBuilder;
import io.grpc.netty.shaded.io.netty.handler.ssl.SslContext;

import java.io.File;
import java.util.concurrent.TimeUnit;

public class InventoryClient {
    private final ManagedChannel channel;
    private final InventoryServiceGrpc.InventoryServiceBlockingStub blockingStub;
    private final InventoryServiceGrpc.InventoryServiceStub asyncStub;
    private final HealthGrpc.HealthBlockingStub healthStub;

    public InventoryClient(String host, int port) throws Exception {
        this(createSecureChannel(host, port));
    }

    private static ManagedChannel createSecureChannel(String host, int port) throws Exception {
        SslContext sslContext = GrpcSslContexts.forClient()
                .trustManager(new File("server.crt"))
                .build();

        return NettyChannelBuilder.forAddress(host, port)
                .sslContext(sslContext)
                .defaultLoadBalancingPolicy("round_robin")
                .enableRetry()
                .maxRetryAttempts(3)
                .build();
    }

    public InventoryClient(ManagedChannel channel) {
        this.channel = channel;
        this.blockingStub = InventoryServiceGrpc.newBlockingStub(channel);
        this.asyncStub = InventoryServiceGrpc.newStub(channel);
        this.healthStub = HealthGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void checkHealth() {
        try {
            HealthCheckResponse response = healthStub
                    .withDeadlineAfter(5, TimeUnit.SECONDS)
                    .check(HealthCheckRequest.newBuilder()
                            .setService("inventory.InventoryService")
                            .build());

            System.out.println("Service health status: " + response.getStatus());
        } catch (StatusRuntimeException e) {
            System.out.println("Health check failed: " + e.getStatus());
        }
    }

    public void updateStock(String productId, int quantityChange) {
        try {
            StockUpdateRequest request = StockUpdateRequest.newBuilder()
                    .setProductId(productId)
                    .setQuantityChange(quantityChange)
                    .build();

            StockUpdateResponse response = blockingStub
                    .withDeadlineAfter(5, TimeUnit.SECONDS)
                    .updateStock(request);

            System.out.println("Stock update successful: " + response.getSuccess());
            System.out.println("Updated product: " + response.getUpdatedProduct());
        } catch (StatusRuntimeException e) {
            System.out.println("RPC failed: " + e.getStatus());
        }
    }

    public void subscribeLowStockAlerts(int threshold) {
        LowStockSubscriptionRequest request = LowStockSubscriptionRequest.newBuilder()
                .setThreshold(threshold)
                .build();

        try {
            blockingStub.withDeadlineAfter(30, TimeUnit.SECONDS)
                    .subscribeLowStockAlerts(request)
                    .forEachRemaining(alert -> {
                        System.out.println("Low stock alert received:");
                        System.out.println("  Product: " + alert.getProduct().getName());
                        System.out.println("  Current quantity: " + alert.getCurrentQuantity());
                        System.out.println("  Threshold: " + alert.getThreshold());
                    });
        } catch (StatusRuntimeException e) {
            System.out.println("RPC failed: " + e.getStatus());
        }
    }

    public static void main(String[] args) throws Exception {
        String host = "localhost";
        int port = 50051;

        InventoryClient client = new InventoryClient(host, port);
        try {
            client.checkHealth();
            client.updateStock("p1", -10);
            client.subscribeLowStockAlerts(20);
        } finally {
            client.shutdown();
        }
    }
}
