import React, { useState, useEffect, useRef } from 'react';
import Post from './Post';
import { connectWebSocket, subscribeToUpdates } from './websocketService';
import { fetchPosts } from './api';
import ErrorBoundary from './ErrorBoundary';
import { useEngagementMetrics } from './hooks/useEngagementMetrics';

function* postGenerator(initialPosts = []) {
  let currentPosts = [...initialPosts];
  let page = 1;

  yield currentPosts;

  while (true) {
    try {
      const newPosts = yield fetchPosts(page++);
      currentPosts = [...currentPosts, ...newPosts];
      yield currentPosts;
    } catch (error) {
      console.error("Failed to fetch more posts:", error);
      yield currentPosts;
    }
  }
}

const Feed = () => {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const postIterator = useRef(null);
  const { trackView, trackEngagement } = useEngagementMetrics();

  useEffect(() => {
    const initFeed = async () => {
      try {
        const initialPosts = await fetchPosts(0);
        postIterator.current = postGenerator(initialPosts);
        postIterator.current.next();
        setPosts(initialPosts);
        setLoading(false);
        trackView('feed');
      } catch (err) {
        setError(err.message);
        setLoading(false);
      }
    };

    initFeed();

    const socket = connectWebSocket();
    const unsubscribe = subscribeToUpdates(socket, (update) => {
      setPosts(currentPosts => {
        const updatedPosts = currentPosts.map(post => 
          post.id === update.postId ? { ...post, ...update.data } : post
        );
        return updatedPosts;
      });
    });

    return () => unsubscribe();
  }, [trackView]);

  const loadMorePosts = async () => {
    setLoading(true);
    try {
      const result = await postIterator.current.next();
      if (!result.done) {
        setPosts(result.value);
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (error && !posts.length) {
    return <div className="feed-error">Failed to load feed: {error}</div>;
  }

  return (
    <div className="feed-container">
      <h1>Your Feed</h1>
      {posts.map(post => (
        <ErrorBoundary key={post.id} fallback={<div>Error loading post</div>}>
          <Post 
            post={post} 
            onEngagement={(type) => trackEngagement(post.id, type)}
          />
        </ErrorBoundary>
      ))}
      {loading && <div className="loading-indicator">Loading more posts...</div>}
      <button 
        onClick={loadMorePosts} 
        disabled={loading}
        className="load-more-btn"
      >
        Load More
      </button>
    </div>
  );
};

export default Feed;
```

