import React, { useState, useCallback } from 'react';
import CommentSection from './CommentSection';
import { updatePostLikes } from './api';

const Post = ({ post, onEngagement }) => {
  const [likes, setLikes] = useState(post.likes);
  const [showComments, setShowComments] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  const handleLike = useCallback(async () => {
    if (isUpdating) return;

    setIsUpdating(true);
    try {
      setLikes(prevLikes => prevLikes + 1);
      onEngagement('like');
      await updatePostLikes(post.id, likes + 1);
    } catch (error) {
      setLikes(prevLikes => prevLikes - 1);
      console.error("Failed to update likes:", error);
    } finally {
      setIsUpdating(false);
    }
  }, [post.id, likes, isUpdating, onEngagement]);

  const toggleComments = useCallback(() => {
    setShowComments(prev => !prev);
    if (!showComments) {
      onEngagement('comment_view');
    }
  }, [showComments, onEngagement]);

  return (
    <div className="post-container">
      <div className="post-header">
        <img src={post.author.avatar} alt={post.author.name} className="avatar" />
        <div className="author-info">
          <h3>{post.author.name}</h3>
          <span className="timestamp">{new Date(post.timestamp).toLocaleString()}</span>
        </div>
      </div>

      <div className="post-content">
        <p>{post.content}</p>
        {post.image && <img src={post.image} alt="Post content" className="post-image" />}
      </div>

      <div className="post-actions">
        <button 
          onClick={handleLike} 
          className={`like-button ${isUpdating ? 'updating' : ''}`}
          disabled={isUpdating}
        >
          👍 {likes}
        </button>
        <button onClick={toggleComments} className="comment-button">
          💬 {post.comments.length} Comments
        </button>
      </div>

      {showComments && (
        <CommentSection 
          postId={post.id} 
          initialComments={post.comments}
          onEngagement={onEngagement}
        />
      )}
    </div>
  );
};

export default React.memo(Post);
