import React, { useState, useEffect } from 'react';
import { addComment, fetchComments } from './api';

const CommentSection = ({ postId, initialComments, onEngagement }) => {
  const [comments, setComments] = useState(initialComments || []);
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadComments = async () => {
      try {
        const latestComments = await fetchComments(postId);
        setComments(latestComments);
      } catch (err) {
        setError("Failed to load comments");
      }
    };

    if (!initialComments) {
      loadComments();
    }
  }, [postId, initialComments]);

  const handleSubmitComment = async (e) => {
    e.preventDefault();
    if (!newComment.trim() || isSubmitting) return;

    setIsSubmitting(true);
    try {
      const comment = await addComment(postId, newComment);
      setComments(prev => [...prev, comment]);
      setNewComment('');
      onEngagement('comment_add');
    } catch (err) {
      setError("Failed to add comment");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="comment-section">
      {error && <div className="error-message">{error}</div>}

      <div className="comments-list">
        {comments.map(comment => (
          <div key={comment.id} className="comment">
            <div className="comment-header">
              <img src={comment.author.avatar} alt={comment.author.name} className="avatar small" />
              <span className="author-name">{comment.author.name}</span>
              <span className="timestamp">{new Date(comment.timestamp).toLocaleString()}</span>
            </div>
            <p className="comment-text">{comment.text}</p>
          </div>
        ))}
        {comments.length === 0 && <p className="no-comments">No comments yet</p>}
      </div>

      <form onSubmit={handleSubmitComment} className="comment-form">
        <textarea
          value={newComment}
          onChange={(e) => setNewComment(e.target.value)}
          placeholder="Write a comment..."
          disabled={isSubmitting}
        />
        <button 
          type="submit" 
          disabled={isSubmitting || !newComment.trim()}
          className={isSubmitting ? 'submitting' : ''}
        >
          {isSubmitting ? 'Posting...' : 'Post'}
        </button>
      </form>
    </div>
  );
};

export default CommentSection;
