import { useCallback, useRef } from 'react';

export const useEngagementMetrics = () => {
  const metrics = useRef({
    viewedPosts: new Set(),
    interactions: [],
    sessionStartTime: Date.now(),
    lastActivityTime: Date.now()
  });

  const trackView = useCallback((viewType, itemId = null) => {
    const timestamp = Date.now();

    if (itemId) {
      metrics.current.viewedPosts.add(itemId);
    }

    // Update session data
    metrics.current.lastActivityTime = timestamp;

    // Send analytics data
    sendAnalyticsEvent({
      type: 'view',
      viewType,
      itemId,
      timestamp,
      sessionDuration: timestamp - metrics.current.sessionStartTime
    });
  }, []);

  const trackEngagement = useCallback((itemId, engagementType) => {
    const timestamp = Date.now();

    // Store interaction
    metrics.current.interactions.push({
      itemId,
      engagementType,
      timestamp
    });

    // Update session data
    metrics.current.lastActivityTime = timestamp;

    // Send analytics data
    sendAnalyticsEvent({
      type: 'engagement',
      engagementType,
      itemId,
      timestamp,
      sessionDuration: timestamp - metrics.current.sessionStartTime
    });
  }, []);

  const getEngagementSummary = useCallback(() => {
    return {
      uniquePostsViewed: metrics.current.viewedPosts.size,
      totalInteractions: metrics.current.interactions.length,
      sessionDuration: Date.now() - metrics.current.sessionStartTime,
      interactionsByType: metrics.current.interactions.reduce((acc, interaction) => {
        acc[interaction.engagementType] = (acc[interaction.engagementType] || 0) + 1;
        return acc;
      }, {})
    };
  }, []);

  return { trackView, trackEngagement, getEngagementSummary };
};

// Helper function to send analytics data
const sendAnalyticsEvent = (data) => {
  // In a real app, this would send data to your analytics service
  if (process.env.NODE_ENV === 'development') {
    console.log('Analytics event:', data);
  } else {
    // Send to analytics service
  }
};
