import { defineStore } from 'pinia';
import { computed, ref } from 'vue';
import { saveConfiguration } from '../api';

export const useConfiguratorStore = defineStore('configurator', () => {
  // State
  const productName = ref('');
  const selectedMaterial = ref(null);
  const selectedColor = ref(null);
  const dimensions = ref({ width: 0, height: 0, depth: 0 });
  const quantity = ref(1);
  const isSaving = ref(false);
  const apiError = ref(null);

  // Base prices
  const materialPrices = {
    wood: 100,
    metal: 200,
    plastic: 50,
    glass: 150
  };

  const colorPrices = {
    standard: 0,
    premium: 30,
    custom: 50
  };

  // Computed
  const totalPrice = computed(() => {
    if (!selectedMaterial.value) return 0;

    const baseMaterialPrice = materialPrices[selectedMaterial.value] || 0;
    const colorPrice = selectedColor.value ? (colorPrices[selectedColor.value.type] || 0) : 0;
    const volumeMultiplier = dimensions.value.width * dimensions.value.height * dimensions.value.depth / 1000;

    return (baseMaterialPrice + colorPrice) * Math.max(1, volumeMultiplier) * quantity.value;
  });

  const isConfigValid = computed(() => {
    return (
      productName.value.trim() !== '' &&
      selectedMaterial.value &&
      selectedColor.value &&
      dimensions.value.width > 0 &&
      dimensions.value.height > 0 &&
      dimensions.value.depth > 0 &&
      quantity.value > 0
    );
  });

  // Actions
  async function saveConfig() {
    if (!isConfigValid.value) return;

    isSaving.value = true;
    apiError.value = null;

    try {
      const config = {
        productName: productName.value,
        material: selectedMaterial.value,
        color: selectedColor.value,
        dimensions: dimensions.value,
        quantity: quantity.value,
        price: totalPrice.value
      };

      const result = await saveConfiguration(config);
      return result;
    } catch (error) {
      apiError.value = error.message || 'Failed to save configuration';
      throw error;
    } finally {
      isSaving.value = false;
    }
  }

  function resetConfig() {
    productName.value = '';
    selectedMaterial.value = null;
    selectedColor.value = null;
    dimensions.value = { width: 0, height: 0, depth: 0 };
    quantity.value = 1;
    apiError.value = null;
  }

  return {
    productName,
    selectedMaterial,
    selectedColor,
    dimensions,
    quantity,
    isSaving,
    apiError,
    totalPrice,
    isConfigValid,
    saveConfig,
    resetConfig
  };
});
