<script setup>
import { computed } from 'vue';
import { useRouter } from 'vue-router';
import { useConfiguratorStore } from '../stores/configurator';

const router = useRouter();
const store = useConfiguratorStore();

const widthError = computed(() => {
  return !store.dimensions.width || store.dimensions.width <= 0 
    ? 'Width must be greater than 0' 
    : null;
});

const heightError = computed(() => {
  return !store.dimensions.height || store.dimensions.height <= 0 
    ? 'Height must be greater than 0' 
    : null;
});

const depthError = computed(() => {
  return !store.dimensions.depth || store.dimensions.depth <= 0 
    ? 'Depth must be greater than 0' 
    : null;
});

const isValid = computed(() => {
  return !widthError.value && !heightError.value && !depthError.value;
});

const volumeMultiplier = computed(() => {
  const { width, height, depth } = store.dimensions;
  if (!width || !height || !depth) return 0;

  return Math.max(1, (width * height * depth) / 1000);
});

function goToNext() {
  if (isValid.value) {
    router.push('/preview');
  }
}

function goToPrevious() {
  router.push('/colors');
}
</script>
