<script setup>
import { ref, onMounted, computed, onBeforeUnmount } from 'vue';
import { useRouter } from 'vue-router';
import { useConfiguratorStore } from '../stores/configurator';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

const router = useRouter();
const store = useConfiguratorStore();
const canvasContainer = ref(null);

let scene, camera, renderer, controls, product;

const hasDimensions = computed(() => {
  return store.dimensions.width > 0 && 
         store.dimensions.height > 0 && 
         store.dimensions.depth > 0;
});

const isConfigComplete = computed(() => {
  return !!store.productName && 
         !!store.selectedMaterial && 
         !!store.selectedColor && 
         hasDimensions.value;
});

onMounted(() => {
  if (isConfigComplete.value) {
    initThreeJs();
    renderProduct();
    window.addEventListener('resize', onWindowResize);
  }
});

onBeforeUnmount(() => {
  if (renderer) {
    window.removeEventListener('resize', onWindowResize);
    canvasContainer.value.removeChild(renderer.domElement);
    renderer.dispose();
  }
});

function initThreeJs() {
  scene = new THREE.Scene();
  scene.background = new THREE.Color(0xf0f0f0);

  camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
  camera.position.z = 5;

  renderer = new THREE.WebGLRenderer({ antialias: true });
  renderer.setSize(canvasContainer.value.clientWidth, canvasContainer.value.clientHeight);
  canvasContainer.value.appendChild(renderer.domElement);

  controls = new OrbitControls(camera, renderer.domElement);
  controls.enableDamping = true;

  const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
  scene.add(ambientLight);

  const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
  directionalLight.position.set(1, 1, 1);
  scene.add(directionalLight);

  animate();
}

function renderProduct() {
  if (product) scene.remove(product);

  const { width, height, depth } = store.dimensions;
  const geometry = new THREE.BoxGeometry(width/100, height/100, depth/100);

  const materialColor = new THREE.Color(store.selectedColor.hex || '#cccccc');
  const material = new THREE.MeshStandardMaterial({ 
    color: materialColor,
    roughness: 0.7,
    metalness: store.selectedMaterial === 'metal' ? 0.8 : 0.1
  });

  product = new THREE.Mesh(geometry, material);
  scene.add(product);

  controls.reset();
}

function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}

function onWindowResize() {
  if (!canvasContainer.value) return;

  camera.aspect = canvasContainer.value.clientWidth / canvasContainer.value.clientHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(canvasContainer.value.clientWidth, canvasContainer.value.clientHeight);
}

function rotateLeft() {
  if (product) product.rotation.y += 0.2;
}

function rotateRight() {
  if (product) product.rotation.y -= 0.2;
}

function zoomIn() {
  camera.position.z -= 0.5;
}

function zoomOut() {
  camera.position.z += 0.5;
}

function resetView() {
  if (controls) controls.reset();
  if (product) {
    product.rotation.set(0, 0, 0);
  }
}

function goToNext() {
  router.push('/summary');
}

function goToPrevious() {
  router.push('/dimensions');
}
</script>
