import Cot from '@cotjs/core';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcrypt';
import { rateLimit } from 'express-rate-limit';
import { body, validationResult } from 'express-validator';
import { logger } from './utils/logger.js';
import { db } from './db/index.js';

const app = new Cot();
const JWT_SECRET = process.env.JWT_SECRET || 'secret_key';

// Rate limiting middleware
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  standardHeaders: true,
  legacyHeaders: false,
});

// Auth middleware
const authenticate = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];
    if (!token) return res.status(401).json({ error: 'Unauthorized' });

    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (error) {
    logger.error('Authentication error', { error: error.message });
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Role validation middleware
const requireRole = (role) => (req, res, next) => {
  if (req.user.role !== role) {
    return res.status(403).json({ error: 'Forbidden' });
  }
  next();
};

// Validation middleware
const validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  next();
};

// User registration
app.post('/api/auth/register', 
  authLimiter,
  [
    body('email').isEmail(),
    body('password').isLength({ min: 8 }),
    body('name').notEmpty(),
    body('role').isIn(['jobseeker', 'employer'])
  ],
  validate,
  async (req, res) => {
    try {
      const { email, password, name, role } = req.body;

      const existingUser = await db.users.findOne({ email });
      if (existingUser) {
        return res.status(409).json({ error: 'User already exists' });
      }

      const hashedPassword = await bcrypt.hash(password, 10);
      const user = await db.users.create({
        email,
        password: hashedPassword,
        name,
        role
      });

      const token = jwt.sign({ id: user.id, email: user.email, role: user.role }, JWT_SECRET, { expiresIn: '1d' });

      logger.info('User registered', { userId: user.id });
      res.status(201).json({ token, user: { id: user.id, email: user.email, name: user.name, role: user.role } });
    } catch (error) {
      logger.error('Registration error', { error: error.message });
      res.status(500).json({ error: 'Server error' });
    }
});

// User login
app.post('/api/auth/login', 
  authLimiter,
  [
    body('email').isEmail(),
    body('password').notEmpty()
  ],
  validate,
  async (req, res) => {
    try {
      const { email, password } = req.body;

      const user = await db.users.findOne({ email });
      if (!user) {
        return res.status(401).json({ error: 'Invalid credentials' });
      }

      const isPasswordValid = await bcrypt.compare(password, user.password);
      if (!isPasswordValid) {
        return res.status(401).json({ error: 'Invalid credentials' });
      }

      const token = jwt.sign({ id: user.id, email: user.email, role: user.role }, JWT_SECRET, { expiresIn: '1d' });

      logger.info('User logged in', { userId: user.id });
      res.json({ token, user: { id: user.id, email: user.email, name: user.name, role: user.role } });
    } catch (error) {
      logger.error('Login error', { error: error.message });
      res.status(500).json({ error: 'Server error' });
    }
});

// Create job listing
app.post('/api/jobs', 
  authenticate,
  requireRole('employer'),
  [
    body('title').notEmpty(),
    body('description').notEmpty(),
    body('company').notEmpty(),
    body('location').notEmpty(),
    body('salary').isNumeric(),
    body('requirements').isArray()
  ],
  validate,
  async (req, res) => {
    try {
      const { title, description, company, location, salary, requirements } = req.body;

      const job = await db.jobs.create({
        title,
        description,
        company,
        location,
        salary,
        requirements,
        employerId: req.user.id,
        createdAt: new Date()
      });

      logger.info('Job created', { jobId: job.id, userId: req.user.id });
      res.status(201).json(job);
    } catch (error) {
      logger.error('Job creation error', { error: error.message });
      res.status(500).json({ error: 'Server error' });
    }
});

// Get all jobs
app.get('/api/jobs', async (req, res) => {
  try {
    const jobs = await db.jobs.findAll();
    res.json(jobs);
  } catch (error) {
    logger.error('Fetch jobs error', { error: error.message });
    res.status(500).json({ error: 'Server error' });
  }
});

// Get job by ID
app.get('/api/jobs/:id', async (req, res) => {
  try {
    const job = await db.jobs.findOne({ id: req.params.id });

    if (!job) {
      return res.status(404).json({ error: 'Job not found' });
    }

    res.json(job);
  } catch (error) {
    logger.error('Fetch job error', { error: error.message, jobId: req.params.id });
    res.status(500).json({ error: 'Server error' });
  }
});

// Update job
app.put('/api/jobs/:id', 
  authenticate,
  requireRole('employer'),
  [
    body('title').notEmpty(),
    body('description').notEmpty(),
    body('location').notEmpty(),
    body('salary').isNumeric()
  ],
  validate,
  async (req, res) => {
    try {
      const job = await db.jobs.findOne({ id: req.params.id });

      if (!job) {
        return res.status(404).json({ error: 'Job not found' });
      }

      if (job.employerId !== req.user.id) {
        return res.status(403).json({ error: 'Not authorized to update this job' });
      }

      const updatedJob = await db.jobs.update(req.params.id, req.body);

      logger.info('Job updated', { jobId: updatedJob.id, userId: req.user.id });
      res.json(updatedJob);
    } catch (error) {
      logger.error('Update job error', { error: error.message, jobId: req.params.id });
      res.status(500).json({ error: 'Server error' });
    }
});

// Delete job
app.delete('/api/jobs/:id', 
  authenticate,
  requireRole('employer'),
  async (req, res) => {
    try {
      const job = await db.jobs.findOne({ id: req.params.id });

      if (!job) {
        return res.status(404).json({ error: 'Job not found' });
      }

      if (job.employerId !== req.user.id) {
        return res.status(403).json({ error: 'Not authorized to delete this job' });
      }

      await db.jobs.delete(req.params.id);

      logger.info('Job deleted', { jobId: req.params.id, userId: req.user.id });
      res.status(204).send();
    } catch (error) {
      logger.error('Delete job error', { error: error.message, jobId: req.params.id });
      res.status(500).json({ error: 'Server error' });
    }
});

// Search jobs
app.get('/api/jobs/search', async (req, res) => {
  try {
    const { keyword, location, minSalary, maxSalary } = req.query;

    let query = {};

    if (keyword) {
      query = {
        ...query,
        $or: [
          { title: { $regex: keyword, $options: 'i' } },
          { description: { $regex: keyword, $options: 'i' } }
        ]
      };
    }

    if (location) {
      query.location = { $regex: location, $options: 'i' };
    }

    if (minSalary || maxSalary) {
      query.salary = {};
      if (minSalary) query.salary.$gte = Number(minSalary);
      if (maxSalary) query.salary.$lte = Number(maxSalary);
    }

    const jobs = await db.jobs.findAll(query);
    res.json(jobs);
  } catch (error) {
    logger.error('Search jobs error', { error: error.message, query: req.query });
    res.status(500).json({ error: 'Server error' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info(`Server running on port ${PORT}`);
});

export default app;
