    health: i32,
    fire_cooldown: Timer,
    damage_animation_timer: Option<Timer>,
}

#[derive(Component)]
struct Projectile {
    speed: f32,
    damage: i32,
}

#[derive(Component)]
struct Enemy {
    speed: f32,
    health: i32,
}

#[derive(Component)]
struct Collider;

#[derive(Component)]
struct Particle {
    lifetime: Timer,
}

#[derive(Component)]
struct ScoreText;

#[derive(Component)]
struct HealthText;

// Resources
struct Score(u32);
struct DifficultySettings {
    enemy_spawn_timer: Timer,
    enemy_speed: f32,
    enemy_health: i32,
}

#[derive(Clone, Eq, PartialEq, Debug, Hash)]
enum GameState {
    MainMenu,
    Playing,
    GameOver,
}

#[derive(Serialize, Deserialize)]
struct HighScore {
    name: String,
    score: u32,
}

struct HighScores(Vec<HighScore>);

// Window resize event handler
fn handle_window_resize(mut resize_event: EventReader<WindowResized>, mut query: Query<&mut Transform, With<Camera>>) {
    for event in resize_event.iter() {
        for mut transform in query.iter_mut() {
            transform.translation.x = event.width / 2.0;
            transform.translation.y = event.height / 2.0;
        }
    }
}

// Player systems
fn spawn_player(mut commands: Commands, asset_server: Res<AssetServer>) {
    commands
        .spawn_bundle(SpriteBundle {
            texture: asset_server.load("textures/player_ship.png"),
            transform: Transform::from_xyz(0.0, -300.0, 1.0),
            ..Default::default()
        })
        .insert(Player {
            speed: 500.0,
            health: 3,
            fire_cooldown: Timer::new(Duration::from_millis(250), false),
            damage_animation_timer: None,
        })
        .insert(Collider);
}

fn player_movement(
    keyboard_input: Res<Input<KeyCode>>,
    time: Res<Time>,
    mut query: Query<(&Player, &mut Transform)>,
    windows: Res<Windows>,
) {
    if let Ok((player, mut transform)) = query.get_single_mut() {
        let window = windows.get_primary().unwrap();
        let window_width = window.width();

        let mut direction = 0.0;
        if keyboard_input.pressed(KeyCode::Left) || keyboard_input.pressed(KeyCode::A) {
            direction -= 1.0;
        }
        if keyboard_input.pressed(KeyCode::Right) || keyboard_input.pressed(KeyCode::D) {
            direction += 1.0;
        }

        let translation = &mut transform.translation;
        translation.x += direction * player.speed * time.delta_seconds();

        // Bound player to screen
        translation.x = translation.x.min(window_width / 2.0 - 40.0).max(-window_width / 2.0 + 40.0);
    }
}

fn player_shooting(
    mut commands: Commands,
    keyboard_input: Res<Input<KeyCode>>,
    time: Res<Time>,
    mut query: Query<(&mut Player, &Transform)>,
    asset_server: Res<AssetServer>,
    audio: Res<Audio>,
) {
    if let Ok((mut player, transform)) = query.get_single_mut() {
        player.fire_cooldown.tick(time.delta());

        if (keyboard_input.pressed(KeyCode::Space) || keyboard_input.pressed(KeyCode::Return)) && player.fire_cooldown.finished() {
            // Shoot projectile
            let projectile_position = transform.translation + Vec3::new(0.0, 50.0, 0.0);

            commands
                .spawn_bundle(SpriteBundle {
                    texture: asset_server.load("textures/laser.png"),
                    transform: Transform::from_translation(projectile_position),
                    ..Default::default()
                })
                .insert(Projectile {
                    speed: 700.0,
                    damage: 1,
                })
                .insert(Collider);

            // Play sound
            audio.play(asset_server.load("sounds/laser_shoot.wav"));

            // Reset cooldown
            player.fire_cooldown.reset();
        }

        // Handle damage animation if active
        if let Some(timer) = &mut player.damage_animation_timer {
            timer.tick(time.delta());
            if timer.finished() {
                player.damage_animation_timer = None;
            }
        }
    }
}

fn player_damage_animation(
    time: Res<Time>,
    mut query: Query<(&Player, &mut TextureAtlasSprite), Changed<Player>>,
) {
    for (player, mut sprite) in query.iter_mut() {
        if player.damage_animation_timer.is_some() {
            // Toggle visibility to create blinking effect
            sprite.index = 1;  // Damaged sprite frame
        } else {
            sprite.index = 0;  // Normal sprite frame
        }
    }
}

// Projectile systems
fn projectile_movement(
    mut commands: Commands,
    time: Res<Time>,
    mut query: Query<(Entity, &Projectile, &mut Transform)>,
    windows: Res<Windows>,
) {
    let window = windows.get_primary().unwrap();
    let window_height = window.height();

    for (entity, projectile, mut transform) in query.iter_mut() {
        transform.translation.y += projectile.speed * time.delta_seconds();

        // Despawn when out of screen
        if transform.translation.y > window_height / 2.0 + 50.0 {
            commands.entity(entity).despawn();
        }
    }
}

// Enemy systems
fn spawn_enemies(
    mut commands: Commands,
    time: Res<Time>,
    mut settings: ResMut<DifficultySettings>,
    asset_server: Res<AssetServer>,
    windows: Res<Windows>,
) {
    settings.enemy_spawn_timer.tick(time.delta());

    if settings.enemy_spawn_timer.finished() {
        let window = windows.get_primary().unwrap();
        let window_width = window.width();

        // Random x position
        let x_position = thread_rng().gen_range(-window_width / 2.0 + 50.0..window_width / 2.0 - 50.0);

        commands
            .spawn_bundle(SpriteBundle {
                texture: asset_server.load("textures/enemy_ship.png"),
                transform: Transform::from_xyz(x_position, window_height / 2.0 + 50.0, 1.0),
                ..Default::default()
            })
            .insert(Enemy {
                speed: settings.enemy_speed,
                health: settings.enemy_health,
            })
            .insert(Collider);

        settings.enemy_spawn_timer.reset();
    }
}

fn enemy_movement(
    mut commands: Commands,
    time: Res<Time>,
    mut query: Query<(Entity, &Enemy, &mut Transform)>,
    windows: Res<Windows>,
) {
    let window = windows.get_primary().unwrap();
    let window_height = window.height();

    for (entity, enemy, mut transform) in query.iter_mut() {
        transform.translation.y -= enemy.speed * time.delta_seconds();

        // Despawn when out of screen
        if transform.translation.y < -window_height / 2.0 - 50.0 {
            commands.entity(entity).despawn();
        }
    }
}

// Collision systems
fn collision_detection(
    mut commands: Commands,
    mut player_query: Query<(&mut Player, &Transform)>,
    enemy_query: Query<(Entity, &Enemy, &Transform)>,
    projectile_query: Query<(Entity, &Projectile, &Transform)>,
    asset_server: Res<AssetServer>,
    audio: Res<Audio>,
    mut score: ResMut<Score>,
) {
    if let Ok((mut player, player_transform)) = player_query.get_single_mut() {
        let player_size = Vec2::new(80.0, 60.0);

        // Check enemy-player collisions
        for (enemy_entity, _enemy, enemy_transform) in enemy_query.iter() {
            let enemy_size = Vec2::new(70.0, 70.0);

            if collide(
                player_transform.translation,
                player_size,
                enemy_transform.translation,
                enemy_size,
            ).is_some() {
                // Player takes damage
                player.health -= 1;
                player.damage_animation_timer = Some(Timer::new(Duration::from_millis(500), false));

                // Spawn explosion
                spawn_explosion(&mut commands, &asset_server, enemy_transform.translation);
                audio.play(asset_server.load("sounds/explosion.wav"));

                // Destroy enemy
                commands.entity(enemy_entity).despawn();

                if player.health <= 0 {
                    // Game over logic would be triggered here through state changes
                }
            }
        }

        // Check projectile-enemy collisions
        for (projectile_entity, projectile, projectile_transform) in projectile_query.iter() {
            let projectile_size = Vec2::new(10.0, 30.0);

            for (enemy_entity, enemy, enemy_transform) in enemy_query.iter() {
                let enemy_size = Vec2::new(70.0, 70.0);

                if collide(
                    projectile_transform.translation,
                    projectile_size,
                    enemy_transform.translation,
                    enemy_size,
                ).is_some() {
                    // Destroy projectile
                    commands.entity(projectile_entity).despawn();

                    // Enemy takes damage
                    let mut enemy_died = false;
                    if let Some(mut enemy_commands) = commands.get_entity(enemy_entity) {
                        enemy_commands.insert(Enemy {
                            speed: enemy.speed,
                            health: enemy.health - projectile.damage,
                        });

                        // Check if enemy is destroyed
                        if enemy.health - projectile.damage <= 0 {
                            enemy_commands.despawn();
                            enemy_died = true;

                            // Increase score
                            score.0 += 100;

                            // Spawn explosion
                            spawn_explosion(&mut commands, &asset_server, enemy_transform.translation);
                            audio.play(asset_server.load("sounds/explosion.wav"));
                        }
                    }

                    if !enemy_died {
                        // Show hit effect
                        spawn_hit_effect(&mut commands, &asset_server, enemy_transform.translation);
                        audio.play(asset_server.load("sounds/hit.wav"));
                    }

                    break;
                }
            }
        }
    }
}

// Particle effects
fn spawn_explosion(commands: &mut Commands, asset_server: &AssetServer, position: Vec3) {
    for _ in 0..20 {
        let angle = thread_rng().gen_range(0.0..std::f32::consts::TAU);
        let velocity = Vec2::new(angle.cos(), angle.sin()) * thread_rng().gen_range(50.0..150.0);
        let lifetime = thread_rng().gen_range(0.5..1.5);

        commands
            .spawn_bundle(SpriteBundle {
                texture: asset_server.load("textures/particle.png"),
                transform: Transform::from_translation(position),
                sprite: Sprite {
                    color: Color::rgb(1.0, 0.5, 0.0),
                    ..Default::default()
                },
                ..Default::default()
            })
            .insert(Particle {
                lifetime: Timer::new(Duration::from_secs_f32(lifetime), false),
            })
            .insert(velocity);
    }
}

fn spawn_hit_effect(commands: &mut Commands, asset_server: &AssetServer, position: Vec3) {
    commands
        .spawn_bundle(SpriteBundle {
            texture: asset_server.load("textures/hit_effect.png"),
            transform: Transform::from_translation(position),
            ..Default::default()
        })
        .insert(Particle {
            lifetime: Timer::new(Duration::from_millis(200), false),
        });
}

fn update_particles(
    mut commands: Commands,
    time: Res<Time>,
    mut query: Query<(Entity, &mut Transform, &mut Particle, Option<&Vec2>)>,
) {
    for (entity, mut transform, mut particle, velocity) in query.iter_mut() {
        particle.lifetime.tick(time.delta());

        if particle.lifetime.finished() {
            commands.entity(entity).despawn();
        } else {
            if let Some(velocity) = velocity {
                transform.translation.x += velocity.x * time.delta_seconds();
                transform.translation.y += velocity.y * time.delta_seconds();
            }
        }
    }
}

