fn update_ui(
    player_query: Query<&Player>,
    mut score_query: Query<&mut Text, (With<ScoreText>, Without<HealthText>)>,
    mut health_query: Query<&mut Text, With<HealthText>>,
    score: Res<Score>,
) {
    // Update score
    if let Ok(mut text) = score_query.get_single_mut() {
        text.sections[0].value = format!("Score: {}", score.0);
    }

    // Update health
    if let Ok(player) = player_query.get_single() {
        if let Ok(mut text) = health_query.get_single_mut() {
            text.sections[0].value = format!("Health: {}", player.health);

            // Change color based on health
            text.sections[0].style.color = match player.health {
                3 => Color::GREEN,
                2 => Color::YELLOW,
                _ => Color::RED,
            };
        }
    }
}

