fn setup_game_over(
    mut commands: Commands, 
    asset_server: Res<AssetServer>,
    score: Res<Score>,
    mut high_scores: ResMut<HighScores>,
) {
    // Save score if it's a high score
    if high_scores.0.is_empty() || score.0 > high_scores.0.iter().map(|hs| hs.score).min().unwrap_or(0) {
        high_scores.0.push(HighScore {
            name: "Player".to_string(),
            score: score.0,
        });

        // Sort and keep only top 10
        high_scores.0.sort_by(|a, b| b.score.cmp(&a.score));
        if high_scores.0.len() > 10 {
            high_scores.0.truncate(10);
        }

        // Save to file
        save_high_scores(&high_scores.0);
    }

    commands.spawn_bundle(UiCameraBundle::default());

    // Game over text
    commands
        .spawn_bundle(TextBundle {
            text: Text::with_section(
                "Game Over",
                TextStyle {
                    font: asset_server.load("fonts/font.ttf"),
                    font_size: 80.0,
                    color: Color::RED,
                },
                TextAlignment {
                    horizontal: HorizontalAlign::Center,
                    ..Default::default()
                },
            ),
            style: Style {
                position_type: PositionType::Absolute,
                position: Rect {
                    top: Val::Px(100.0),
                    left: Val::Percent(50.0),
                    ..Default::default()
                },
                margin: Rect {
                    left: Val::Px(-200.0),
                    ..Default::default()
                },
                ..Default::default()
            },
            ..Default::default()
        });

    // Score display
    commands
        .spawn_bundle(TextBundle {
            text: Text::with_section(
                format!("Final Score: {}", score.0),
                TextStyle {
                    font: asset_server.load("fonts/font.ttf"),
                    font_size: 40.0,
                    color: Color::WHITE,
                },
                TextAlignment {
                    horizontal: HorizontalAlign::Center,
                    ..Default::default()
                },
            ),
            style: Style {
                position_type: PositionType::Absolute,
                position: Rect {
                    top: Val::Px(200.0),
                    left: Val::Percent(50.0),
                    ..Default::default()
                },
                margin: Rect {
                    left: Val::Px(-150.0),
                    ..Default::default()
                },
                ..Default::default()
            },
            ..Default::default()
        });

    // Main menu button
    commands
        .spawn_bundle(ButtonBundle {
            style: Style {
                size: Size::new(Val::Px(200.0), Val::Px(65.0)),
                position_type: PositionType::Absolute,
                position: Rect {
                    bottom: Val::Px(100.0),
                    left: Val::Percent(50.0),
                    ..Default::default()
                },
                margin: Rect {
                    left: Val::Px(-100.0),
                    ..Default::default()
                },
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..Default::default()
            },
            color: UiColor(Color::rgb(0.15, 0.15, 0.15)),
            ..Default::default()
        })
        .with_children(|parent| {
            parent.spawn_bundle(TextBundle {
                text: Text::with_section(
                    "Main Menu",
                    TextStyle {
                        font: asset_server.load("fonts/font.ttf"),
                        font_size: 40.0,
                        color: Color::WHITE,
                    },
                    TextAlignment::default(),
                ),
                ..Default::default()
            });
        });
}

fn game_over_interaction(
    mut state: ResMut<State<GameState>>,
    interaction_query: Query<&Interaction, (Changed<Interaction>, With<Button>)>,
) {
    for interaction in interaction_query.iter() {
        if *interaction == Interaction::Clicked {
            state.set(GameState::MainMenu).unwrap();
        }
    }
}

// High score functionality
fn save_high_scores(high_scores: &[HighScore]) {
    if let Ok(file) = File::create("high_scores.json") {
        serde_json::to_writer(file, high_scores).unwrap();
    }
}

fn load_high_scores() -> Vec<HighScore> {
    match File::open("high_scores.json") {
        Ok(file) => {
            let reader = BufReader::new(file);
            match serde_json::from_reader(reader) {
                Ok(scores) => scores,
                Err(_) => Vec::new(),
            }
        }
        Err(_) => Vec::new(),
    }
}

// Difficulty plugin
struct DifficultyPlugin;

impl Plugin for DifficultyPlugin {
    fn build(&self, app: &mut App) {
        app.insert_resource(DifficultySettings {
            enemy_spawn_timer: Timer::new(Duration::from_secs(1), true),
            enemy_speed: 100.0,
            enemy_health: 1,
        });

        app.add_system(update_difficulty);
    }
}

fn update_difficulty(mut settings: ResMut<DifficultySettings>, score: Res<Score>) {
    // Increase difficulty based on score
    let score_val = score.0;

    if score_val > 5000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(500), true);
        settings.enemy_speed = 200.0;
        settings.enemy_health = 3;
    } else if score_val > 2000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(700), true);
        settings.enemy_speed = 150.0;
        settings.enemy_health = 2;
    } else if score_val > 1000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(900), true);
        settings.enemy_speed = 130.0;
        settings.enemy_health = 1;
    }
}

fn main() {
    App::new()
        .insert_resource(WindowDescriptor {
            title: "Space Shooter".to_string(),
            width: 800.0,
            height: 600.0,
            vsync: true,
            resizable: true,
            present_mode: PresentMode::Fifo,
            ..Default::default()
        })
        .insert_resource(Score(0))
        .insert_resource(HighScores(load_high_scores()))
        .add_state(GameState::MainMenu)
        .add_plugins(DefaultPlugins)
        .add_plugin(DifficultyPlugin)
        .add_system(handle_window_resize)
        .add_system_set(
            SystemSet::on_enter(GameState::MainMenu)
                .with_system(setup_menu)
        )
        .add_system_set(
            SystemSet::on_update(GameState::MainMenu)
                .with_system(menu_interaction)
        )
        .add_system_set(
            SystemSet::on_enter(GameState::Playing)
                .with_system(setup_ui)
                .with_system(spawn_player)
        )
        .add_system_set(
            SystemSet::on_update(GameState::Playing)
                .with_system(player_movement)
                .with_system(player_shooting)
                .with_system(player_damage_animation)
                .with_system(projectile_movement)
                .with_system(spawn_enemies)
                .with_system(enemy_movement)
                .with_system(collision_detection)
                .with_system(update_particles)
                .with_system(update_ui)
        )
        .add_system_set(
            SystemSet::on_enter(GameState::GameOver)
                .with_system(setup_game_over)
        )
        .add_system_set(
            SystemSet::on_update(GameState::GameOver)
                .with_system(game_over_interaction)
        )
        .run();
}
