import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.datastores.jpa.transaction.NonJtaTransaction;
import com.yahoo.elide.graphql.GraphQLSettings;
import com.yahoo.elide.standalone.config.ElideStandaloneSettings;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;

import javax.persistence.EntityManagerFactory;
import java.util.HashMap;
import java.util.Map;
import java.util.TimeZone;

@SpringBootApplication
public class CatalogApplication {
    public static void main(String[] args) {
        SpringApplication.run(CatalogApplication.class, args);
    }

    @Bean
    public ElideStandaloneSettings elideSettings(EntityManagerFactory entityManagerFactory) {
        return new ElideStandaloneSettings() {
            @Override
            public DataStore getDataStore(EntityDictionary dictionary) {
                return new JpaDataStore(
                    () -> { return entityManagerFactory.createEntityManager(); },
                    (em) -> { return new NonJtaTransaction(em); }
                );
            }

            @Override
            public ElideSettings getElideSettings() {
                return ElideSettings.builder()
                    .entityDictionary(getEntityDictionary())
                    .maxPageSize(100)
                    .defaultPageSize(25)
                    .build();
            }

            @Override
            public GraphQLSettings getGraphQLSettings() {
                return GraphQLSettings.builder()
                    .pagination(true)
                    .build();
            }

            @Override
            public Map<String, Class<?>> getCheckMappings() {
                Map<String, Class<?>> checks = new HashMap<>();
                checks.put("user is admin", com.catalog.security.UserChecks.class);
                checks.put("user is authenticated", com.catalog.security.UserChecks.class);
                return checks;
            }
        };
    }
}
