#ifndef SENSOR_VALIDATOR_H
#define SENSOR_VALIDATOR_H

#include <cstdint>
#include <string>

enum class SensorType {
    TEMPERATURE,
    PRESSURE,
    HUMIDITY,
    ACCELERATION
};

struct SensorData {
    SensorType type;
    double value;
    std::string format;
    uint32_t checksum;
    void* rawData;
    size_t rawDataSize;
};

class SensorValidator {
public:
    bool validateRange(const SensorData& data);
    bool validateFormat(const SensorData& data);
    bool validateChecksum(const SensorData& data);
    bool validate(const SensorData& data);

private:
    bool isInValidRange(SensorType type, double value);
    bool isValidFormat(const std::string& format, SensorType type);
    uint32_t calculateChecksum(const void* data, size_t size);
};

// C interface
extern "C" {
    typedef struct CSensorData {
        int type;
        double value;
        char format[32];
        uint32_t checksum;
        void* rawData;
        size_t rawDataSize;
    } CSensorData;

    int validateSensorData(const CSensorData* data);
}

#endif
