```cpp:sensor_validator.cpp
#include "sensor_validator.h"
#include <cstring>

bool SensorValidator::validateRange(const SensorData& data) {
    return isInValidRange(data.type, data.value);
}

bool SensorValidator::validateFormat(const SensorData& data) {
    return isValidFormat(data.format, data.type);
}

bool SensorValidator::validateChecksum(const SensorData& data) {
    if (!data.rawData || data.rawDataSize == 0) {
        return false;
    }
    return calculateChecksum(data.rawData, data.rawDataSize) == data.checksum;
}

bool SensorValidator::validate(const SensorData& data) {
    return validateRange(data) && validateFormat(data) && validateChecksum(data);
}

bool SensorValidator::isInValidRange(SensorType type, double value) {
    switch (type) {
        case SensorType::TEMPERATURE: return value >= -50.0 && value <= 150.0;
        case SensorType::PRESSURE: return value >= 0.0 && value <= 500.0;
        case SensorType::HUMIDITY: return value >= 0.0 && value <= 100.0;
        case SensorType::ACCELERATION: return value >= -20.0 && value <= 20.0;
        default: return false;
    }
}

bool SensorValidator::isValidFormat(const std::string& format, SensorType type) {
    if (format.empty()) return false;

    switch (type) {
        case SensorType::TEMPERATURE: return format == "C" || format == "F";
        case SensorType::PRESSURE: return format == "Pa" || format == "bar";
        case SensorType::HUMIDITY: return format == "%";
        case SensorType::ACCELERATION: return format == "m/s^2" || format == "g";
        default: return false;
    }
}

uint32_t SensorValidator::calculateChecksum(const void* data, size_t size) {
    const uint8_t* bytes = static_cast<const uint8_t*>(data);
    uint32_t checksum = 0;
    for (size_t i = 0; i < size; i++) {
        checksum += bytes[i];
    }
    return checksum;
}

// C interface implementation
int validateSensorData(const CSensorData* data) {
    if (!data) return 0;

    SensorData cppData;
    cppData.type = static_cast<SensorType>(data->type);
    cppData.value = data->value;
    cppData.format = data->format;
    cppData.checksum = data->checksum;
    cppData.rawData = data->rawData;
    cppData.rawDataSize = data->rawDataSize;

    SensorValidator validator;
    return validator.validate(cppData) ? 1 : 0;
}
