package com.hospital.model;

import com.yahoo.elide.annotation.*;
import lombok.Data;

import javax.persistence.*;
import java.time.Duration;
import java.time.LocalDateTime;

@Include(rootLevel = true)
@ReadPermission(expression = "user is admin OR user is appointmentParticipant")
@UpdatePermission(expression = "user is admin OR user is doctor")
@CreatePermission(expression = "user is admin OR user is doctor OR user is patient")
@Entity
@Data
@Audited
public class Appointment {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @ManyToOne
    @JoinColumn(name = "patient_id", nullable = false)
    private Patient patient;

    @ManyToOne
    @JoinColumn(name = "doctor_id", nullable = false)
    private Doctor doctor;

    @Column(nullable = false)
    private LocalDateTime scheduledStart;

    @Column(nullable = false)
    private LocalDateTime scheduledEnd;

    @Column
    private LocalDateTime actualStart;

    @Column
    private LocalDateTime actualEnd;

    @Column
    @Enumerated(EnumType.STRING)
    private AppointmentStatus status = AppointmentStatus.SCHEDULED;

    @Column
    private String notes;

    @Version
    private Long version;

    @Transient
    public Duration getWaitTime() {
        if (actualStart != null && scheduledStart != null) {
            return Duration.between(scheduledStart, actualStart);
        }
        return null;
    }

    @Transient
    public boolean isAppointmentParticipant(Object user) {
        if (user instanceof User) {
            String username = ((User) user).getUsername();
            return username.equals(patient.getUsername()) || username.equals(doctor.getUsername());
        }
        return false;
    }

    public enum AppointmentStatus {
        SCHEDULED, COMPLETED, CANCELLED, NO_SHOW
    }
}
