```java:src/main/java/com/hospital/validation/AppointmentValidator.java
package com.hospital.validation;

import com.hospital.model.Appointment;
import com.hospital.repository.AppointmentRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Component;

import javax.validation.ConstraintValidator;
import javax.validation.ConstraintValidatorContext;
import java.time.LocalDateTime;
import java.util.List;

@Component
public class AppointmentValidator implements ConstraintValidator<ValidAppointment, Appointment> {

    @Autowired
    private AppointmentRepository appointmentRepository;

    @Override
    public boolean isValid(Appointment appointment, ConstraintValidatorContext context) {
        if (appointment.getScheduledStart() == null || appointment.getScheduledEnd() == null) {
            return false;
        }

        if (appointment.getScheduledStart().isAfter(appointment.getScheduledEnd())) {
            context.disableDefaultConstraintViolation();
            context.buildConstraintViolationWithTemplate("Appointment end time must be after start time")
                   .addConstraintViolation();
            return false;
        }

        // Check for conflicts with doctor's schedule
        List<Appointment> doctorAppointments = appointmentRepository.findByDoctorAndDateRange(
            appointment.getDoctor(),
            appointment.getScheduledStart().toLocalDate(),
            appointment.getScheduledEnd().toLocalDate()
        );

        for (Appointment existing : doctorAppointments) {
            if (appointment.getId() != null && appointment.getId().equals(existing.getId())) {
                continue; // Skip self when updating
            }

            if (hasTimeConflict(appointment, existing)) {
                context.disableDefaultConstraintViolation();
                context.buildConstraintViolationWithTemplate("Doctor has a conflicting appointment")
                       .addConstraintViolation();
                return false;
            }
        }

        // Check for conflicts with patient's schedule
        List<Appointment> patientAppointments = appointmentRepository.findByPatientAndDateRange(
            appointment.getPatient(),
            appointment.getScheduledStart().toLocalDate(),
            appointment.getScheduledEnd().toLocalDate()
        );

        for (Appointment existing : patientAppointments) {
            if (appointment.getId() != null && appointment.getId().equals(existing.getId())) {
                continue; // Skip self when updating
            }

            if (hasTimeConflict(appointment, existing)) {
                context.disableDefaultConstraintViolation();
                context.buildConstraintViolationWithTemplate("Patient has a conflicting appointment")
                       .addConstraintViolation();
                return false;
            }
        }

        return true;
    }

    private boolean hasTimeConflict(Appointment a1, Appointment a2) {
        // Check if a1 starts during a2
        boolean a1StartsInA2 = !a1.getScheduledStart().isBefore(a2.getScheduledStart()) && 
                               a1.getScheduledStart().isBefore(a2.getScheduledEnd());

        // Check if a1 ends during a2
        boolean a1EndsInA2 = a1.getScheduledEnd().isAfter(a2.getScheduledStart()) && 
                             !a1.getScheduledEnd().isAfter(a2.getScheduledEnd());

        // Check if a1 contains a2
        boolean a1ContainsA2 = a1.getScheduledStart().isBefore(a2.getScheduledStart()) && 
                               a1.getScheduledEnd().isAfter(a2.getScheduledEnd());

        return a1StartsInA2 || a1EndsInA2 || a1ContainsA2;
    }
}
