```java:src/main/java/com/hospital/analytics/AppointmentAnalytics.java
package com.hospital.analytics;

import com.hospital.model.Appointment;
import com.hospital.model.Doctor;
import com.hospital.repository.AppointmentRepository;
import com.yahoo.elide.annotation.*;
import lombok.Data;

import javax.persistence.*;
import java.time.Duration;
import java.time.LocalDate;
import java.util.List;
import java.util.OptionalDouble;

@Include(rootLevel = true)
@ReadPermission(expression = "user is admin OR user is doctor")
@Entity
@Data
public class AppointmentAnalytics {
    @Id
    private Long id = 1L; // Singleton

    @Transient
    private AppointmentRepository appointmentRepository;

    @ComputedAttribute
    public double getAverageWaitTimeInMinutes() {
        List<Appointment> completedAppointments = appointmentRepository.findAll().stream()
            .filter(a -> a.getStatus() == Appointment.AppointmentStatus.COMPLETED && a.getActualStart() != null)
            .toList();

        OptionalDouble average = completedAppointments.stream()
            .mapToLong(a -> a.getWaitTime().toMinutes())
            .average();

        return average.orElse(0.0);
    }

    @ComputedAttribute
    public double getAverageWaitTimeByDoctor(Long doctorId) {
        List<Appointment> completedAppointments = appointmentRepository.findAll().stream()
            .filter(a -> a.getStatus() == Appointment.AppointmentStatus.COMPLETED && 
                   a.getActualStart() != null && 
                   a.getDoctor().getId().equals(doctorId))
            .toList();

        OptionalDouble average = completedAppointments.stream()
            .mapToLong(a -> a.getWaitTime().toMinutes())
            .average();

        return average.orElse(0.0);
    }

    @ComputedAttribute
    public int getNoShowRate() {
        List<Appointment> allAppointments = appointmentRepository.findAll();
        if (allAppointments.isEmpty()) {
            return 0;
        }

        long noShows = allAppointments.stream()
            .filter(a -> a.getStatus() == Appointment.AppointmentStatus.NO_SHOW)
            .count();

        return (int) ((noShows * 100.0) / allAppointments.size());
    }
}
