import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.LocalDateTime;

public class AuditLogger {
    private static final Logger log = LoggerFactory.getLogger(AuditLogger.class);

    @LifeCycleHookBinding(operation = LifeCycleHookBinding.Operation.READ, phase = LifeCycleHookBinding.TransactionPhase.POSTCOMMIT)
    public void logPatientAccess(Patient patient, RequestScope scope) {
        ElideUser elideUser = scope.getUser();
        User user = (User) elideUser.getOpaqueUser();

        log.info("AUDIT: User '{}' with roles {} accessed patient record for {} {} at {}",
                user.getUsername(),
                user.getRoles(),
                patient.getFirstName(),
                patient.getLastName(),
                LocalDateTime.now());
    }

    @LifeCycleHookBinding(operation = LifeCycleHookBinding.Operation.READ, phase = LifeCycleHookBinding.TransactionPhase.POSTCOMMIT)
    public void logMedicalRecordAccess(MedicalRecord record, RequestScope scope) {
        ElideUser elideUser = scope.getUser();
        User user = (User) elideUser.getOpaqueUser();

        log.info("AUDIT: User '{}' with roles {} accessed medical record ID {} for patient {} {} at {}",
                user.getUsername(),
                user.getRoles(),
                record.getId(),
                record.getPatient().getFirstName(),
                record.getPatient().getLastName(),
                LocalDateTime.now());
    }

    @LifeCycleHookBinding(operation = LifeCycleHookBinding.Operation.UPDATE, phase = LifeCycleHookBinding.TransactionPhase.PRECOMMIT)
    public void logAppointmentStatusChange(Appointment appointment, RequestScope scope) {
        ElideUser elideUser = scope.getUser();
        User user = (User) elideUser.getOpaqueUser();

        log.info("AUDIT: User '{}' with roles {} updated appointment ID {} status to {} at {}",
                user.getUsername(),
