package com.hospital.config;

import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideSettingsBuilder;
import com.yahoo.elide.core.datastore.DataStore;
import com.yahoo.elide.core.datastore.inmemory.HashMapDataStore;
import com.yahoo.elide.core.dictionary.EntityDictionary;
import com.yahoo.elide.core.filter.dialect.RSQLFilterDialect;
import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.graphql.GraphQLSettings;
import com.yahoo.elide.spring.config.ElideConfigProperties;
import org.hibernate.SessionFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.persistence.EntityManagerFactory;
import java.util.HashMap;
import java.util.TimeZone;

@Configuration
public class ElideConfig {

    @Bean
    public Elide initializeElide(EntityManagerFactory emf, ElideConfigProperties settings) {
        DataStore jpaDataStore = new JpaDataStore(
                () -> emf.createEntityManager(),
                emf::getMetamodel
        );

        EntityDictionary dictionary = new EntityDictionary(new HashMap<>());

        // Configure sorting and filtering
        RSQLFilterDialect rsqlFilterDialect = new RSQLFilterDialect(dictionary);

        return new Elide(new ElideSettingsBuilder(jpaDataStore)
                .withEntityDictionary(dictionary)
                .withJoinFilterDialect(rsqlFilterDialect)
                .withSubqueryFilterDialect(rsqlFilterDialect)
                .withAuditLogger(new com.yahoo.elide.core.audit.Slf4jLogger())
                .withISO8601Dates("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", TimeZone.getTimeZone("UTC"))
                .withGraphQLSettings(GraphQLSettings.builder().build())
                .build());
    }
}
